insert into public.aulas
  (id, tenant_id, modulo_id, titulo, tipo_conteudo, url_midia, conteudo_texto, ordem, is_global, slides, xp_reward)
values
('1d40f7d1-1331-4ed8-9a3b-45f28b5d020b', NULL, '42e7bcde-c45f-4e69-ae88-866603030ff3', 'O que realmente é vender', 'texto', NULL, NULL, 0, false, '[{"titulo":"O que realmente é vender","corpo":"Vender não é convencer alguém a comprar algo. **Vender é ajudar uma pessoa a tomar a melhor decisão para ela** — e quando essa decisão envolve seu produto, a venda acontece naturalmente.\nZig Ziglar: \"Você pode ter tudo na vida que quiser, se ajudar outras pessoas suficientes a conseguir o que elas querem.\"","tipo":"texto"},{"titulo":"O vendedor como médico","corpo":"Pense num médico de confiança. Ele não entra no consultório dizendo: \"Tenho um remédio ótimo aqui, você precisa comprar.\" Ele escuta, faz perguntas, diagnostica e só então prescreve. O vendedor de elite faz exatamente isso. A venda é a prescrição. O produto é o remédio.","tipo":"texto"},{"titulo":"O que separa vendedores comuns de vendedores de elite","corpo":"- Vendedor Comum — Vendedor de Elite\n- Fala 80% do tempo — Escuta 70% do tempo\n- Vende produtos — Vende resultados\n- Reage ao cliente — Conduz o cliente\n- Teme objeções — Usa objeções a favor\n- Foca no preço — Foca no valor\n- Fecha uma venda — Abre um relacionamento","tipo":"texto"},{"titulo":"Como as pessoas tomam decisões","corpo":"Em 1994, o neurocientista António Damásio estudou pacientes com danos na área emocional do cérebro. Resultado: essas pessoas eram incapazes de tomar decisões simples. **Conclusão: sem emoção, não há decisão.**","tipo":"texto"},{"titulo":"O modelo dos três cérebros","corpo":"- **Cérebro Reptiliano (instintivo):** controla sobrevivência e medo. Pergunta: \"Isso é seguro? Posso confiar?\"\n- **Cérebro Límbico (emocional):** controla sentimentos e memórias. Pergunta: \"Como isso me faz sentir?\" — É aqui que as decisões de compra são tomadas.\n- **Neocórtex (racional):** controla lógica e análise. Pergunta: \"Isso faz sentido?\" — Justifica a decisão, não a toma.\n**Implicação prática:** Se você atacar só o racional (preço, especificações técnicas), está falando com o departamento errado.","tipo":"texto"},{"titulo":"Por que as pessoas compram de verdade","corpo":"Pessoas não compram produtos. Compram:\n- Versões melhores de si mesmas\n- Solução para uma dor\n- Satisfação de um desejo\n- Status social\n- Segurança e pertencimento\n- Experiências e memórias\n**Exemplo:** Um homem não compra uma camisa social. Compra confiança para uma entrevista de emprego. Quando você entende o que o cliente está realmente comprando, sua linguagem muda completamente.","tipo":"texto"},{"titulo":"A equação real da compra","corpo":"Emoção desperta o desejo → Lógica justifica a decisão → Ação (compra)\nO erro mais comum: atacar a lógica antes de despertar a emoção.\n**Estudo de caso — Apple vs. Mercado (2001):** Todos vendiam \"1GB de armazenamento\". A Apple lançou o iPod com: \"1.000 músicas no seu bolso.\" Mesma informação. A Apple ativou a emoção.","tipo":"texto"},{"titulo":"Os 8 gatilhos mentais fundamentais","corpo":"","tipo":"texto"},{"titulo":"1. Reciprocidade","corpo":"Quando alguém nos dá algo, sentimos obrigação de retribuir. No varejo: ofereça informação útil antes de pedir a compra.","tipo":"texto"},{"titulo":"2. Autoridade","corpo":"Seguimos pessoas que percebemos como especialistas. No varejo: demonstre conhecimento profundo dos produtos.","tipo":"texto"},{"titulo":"3. Prova Social","corpo":"Quando não sabemos o que fazer, olhamos o que outros fazem. Exemplo: \"Esse modelo é disparado o mais vendido — saímos com mais de 30 por semana.\"","tipo":"texto"},{"titulo":"4. Escassez","corpo":"Valorizamos mais o que é raro ou pode acabar. **Regra de ouro: só use escassez real.** Escassez falsa é manipulação — e você perde a confiança para sempre.","tipo":"texto"},{"titulo":"5. Afinidade","corpo":"Compramos de pessoas que gostamos. Encontre pontos em comum. Elogie escolhas, não a pessoa.","tipo":"texto"},{"titulo":"6. Consistência","corpo":"Queremos ser coerentes com o que dissemos antes. Pequenos \"sins\" ao longo do atendimento constroem momentum para o grande \"sim\".","tipo":"texto"},{"titulo":"7. Ancoragem","corpo":"O primeiro número que ouvimos serve de referência para tudo que vem depois. Mostre sempre o produto mais caro primeiro.","tipo":"texto"},{"titulo":"8. Percepção de Valor","corpo":"**Preço é o que o cliente paga. Valor é o que ele percebe que está recebendo.** A venda trava quando o preço supera o valor percebido. Sua função é aumentar o valor percebido até superar o preço.","tipo":"texto"},{"titulo":"Confiança: o ativo mais importante","corpo":"Antes de comprar qualquer produto, o cliente compra você. Os quatro pilares:\n- Competência — você sabe do que está falando\n- Honestidade — você fala a verdade mesmo quando prejudica a venda\n- Intenção — o cliente percebe que você está a favor dele\n- Consistência — você age da mesma forma sempre","tipo":"texto"},{"titulo":"Persuasão ética vs. manipulação","corpo":"**Persuasão:** apresenta informações verdadeiras, ativa emoções legítimas e conduz o cliente a uma decisão boa para ele.\n**Manipulação:** distorce, omite, pressiona ou cria urgência falsa para que o cliente tome uma decisão que serve a você, não a ele.\nRegra de ouro: após a compra, o cliente deve se sentir ainda melhor do que antes.","tipo":"texto"}]'::jsonb, 10),
('1e814d63-ec59-46be-845a-5138db580102', NULL, 'c019553d-d803-46b9-bc24-0a5c2d85275b', 'Psicologia do consumidor', 'texto', NULL, NULL, 0, false, '[{"titulo":"Comportamento humano nas compras","corpo":"Todo comportamento humano tem uma causa. O vendedor de elite é, antes de tudo, um estudante do comportamento humano — não por frieza, mas porque entender pessoas é o único caminho para genuinamente ajudá-las.","tipo":"texto"},{"titulo":"A Hierarquia de Maslow aplicada ao varejo","corpo":"- **Necessidades Fisiológicas:** produtos essenciais. Argumento: funcionalidade, durabilidade, custo-benefício.\n- **Necessidades de Segurança:** garantias, proteção. Argumento: garantia estendida, reputação da marca.\n- **Necessidades Sociais:** moda, presentes. Argumento: o que outras pessoas usam, tendências.\n- **Necessidades de Estima:** marcas premium, exclusividade. Argumento: diferenciação, qualidade superior.\n- **Autorrealização:** produtos de alto desempenho. Argumento: potencial desbloqueado, evolução pessoal.","tipo":"texto"},{"titulo":"Os quatro perfis de clientes","corpo":"","tipo":"texto"},{"titulo":"Perfil 1 — O Dominante","corpo":"Fala rápido, quer eficiência, toma decisões rapidamente, foca em resultados, pode parecer impaciente.\n**Como atender:** seja direto e objetivo. Apresente fatos e resultados. Não seja servil — ele respeita quem tem postura.\nExemplo: \"Vou direto ao ponto: esse modelo tem o melhor custo-benefício da categoria por esses três motivos...\"\n**Erros a evitar:** enrolar, ser excessivamente informal, não ter respostas na ponta da língua.","tipo":"texto"},{"titulo":"Perfil 2 — O Influenciador","corpo":"Extrovertido, comunicativo, decide pela emoção e intuição, influenciado por tendências e popularidade.\n**Como atender:** seja caloroso e energético. Use histórias de outros clientes. Fale sobre tendências.\nExemplo: \"Que ótima escolha — todo mundo que vê fica apaixonado. Você tem muito bom gosto...\"\n**Erros a evitar:** ser frio ou excessivamente técnico, não mostrar entusiasmo.","tipo":"texto"},{"titulo":"Perfil 3 — O Estável","corpo":"Calmo, gentil, prefere relacionamentos de longo prazo, decide devagar, precisa de segurança e validação.\n**Como atender:** seja paciente. Mostre garantias e suporte pós-venda. Nunca apresse a decisão.\nExemplo: \"Pode ficar à vontade, sem pressa. Vou te mostrar as opções e a gente vai encontrar o que faz mais sentido pra você.\"\n**Erros a evitar:** pressionar para fechar rápido, dar muitas opções de uma vez.","tipo":"texto"},{"titulo":"Perfil 4 — O Analítico","corpo":"Pesquisa antes de comprar, quer dados e comparações, decide devagar com muita análise, desconfia de argumentos emocionais.\n**Como atender:** tenha informações técnicas precisas. Mostre comparativos e certificações. Nunca apresse.\nExemplo: \"Posso te mostrar uma comparação técnica entre esses dois modelos? Vou explicar o que cada especificação significa na prática...\"\n**Erros a evitar:** exagerar ou generalizar, responder com imprecisão.","tipo":"texto"},{"titulo":"Como identificar o perfil em 30-60 segundos","corpo":"- **Velocidade de movimento:** rápido (Dominante/Influenciador) ou lento (Estável/Analítico)\n- **O que toca primeiro:** lê etiqueta técnica (Analítico), olha o visual (Influenciador), verifica preço (Analítico/Estável)\n- **Como responde à abordagem:** direto = Dominante; animado = Influenciador; sorridente mas tímido = Estável; pergunta técnica imediata = Analítico","tipo":"texto"},{"titulo":"Linguagem corporal","corpo":"Albert Mehrabian (UCLA): 55% do impacto vem da linguagem corporal, 38% do tom de voz, 7% das palavras.","tipo":"texto"},{"titulo":"Sinais de interesse positivo","corpo":"- Inclina o corpo em direção ao produto\n- Pega o produto nas mãos e examina\n- Faz perguntas (qualquer pergunta é sinal de interesse)\n- Toca o produto com carinho","tipo":"texto"},{"titulo":"Sinais de decisão iminente","corpo":"- Para de comparar e foca em um produto\n- Pergunta sobre logística (\"tem entrega?\", \"posso parcelar?\")\n- Visualiza o uso (\"eu podia usar aqui...\")\n- Segura o produto sem querer largar","tipo":"texto"},{"titulo":"Vieses cognitivos aplicados ao varejo","corpo":"","tipo":"texto"},{"titulo":"Efeito de Dotação","corpo":"Valorizamos mais o que sentimos que já é nosso. Deixe o cliente pegar o produto nas mãos — quanto mais ele \"possuir\" mentalmente, mais vai valorizar.","tipo":"texto"},{"titulo":"Paradoxo da Escolha","corpo":"Mais opções = mais dificuldade de decidir = menos vendas. Não mostre 12 opções. Mostre 2 ou 3 e guie a escolha.","tipo":"texto"},{"titulo":"Efeito Halo","corpo":"Uma característica positiva faz a pessoa assumir que outras também são positivas. Destaque o principal diferencial primeiro.","tipo":"texto"},{"titulo":"Aversão à Perda","corpo":"Perder algo dói mais do que ganhar algo equivalente agrada. Em vez de \"você vai ganhar X\", use \"você vai evitar perder X\".","tipo":"texto"},{"titulo":"Enquadramento","corpo":"\"5% de chance de dar errado\" vs. \"95% de chance de dar certo\" — mesma estatística, percepções opostas. Sempre enquadre positivamente.","tipo":"texto"}]'::jsonb, 10),
('f9fbf102-5819-496d-abdc-82cd6a84924a', NULL, '976a3340-f6cf-4f38-9aa6-72b4dc9f1a76', 'Comunicação de alto nível', 'texto', NULL, NULL, 0, false, '[{"titulo":"Rapport: a fundação de toda venda","corpo":"Rapport é o estado de confiança e sintonia entre duas pessoas. **Sem rapport, não há venda — há, no máximo, transação.** E transações não constroem clientes fiéis.","tipo":"texto"},{"titulo":"Como construir rapport em 90 segundos","corpo":"- **Espelhamento:** copie sutilmente a postura, o ritmo de fala e o vocabulário do cliente.\n- **Calibragem:** ajuste sua energia ao nível do cliente. Cliente agitado? Combine a energia e vá suavizando.\n- **Sincronização vocal:** velocidade, volume e tom similares criam sintonia inconsciente.\n- **Interesse genuíno:** faça perguntas sobre o que o cliente diz, não sobre o que você quer vender.\n- **Pacing and leading:** primeiro acompanhe (pacing) o cliente onde ele está — depois conduza (leading) para onde você quer que ele vá. Tentar liderar sem acompanhar primeiro é o erro mais comum.","tipo":"texto"},{"titulo":"Escuta ativa","corpo":"A maioria das pessoas ouve para responder. O vendedor de elite ouve para entender.","tipo":"texto"},{"titulo":"Os cinco níveis de escuta","corpo":"- **Nível 1 — Ignorar:** fisicamente presente, mentalmente ausente.\n- **Nível 2 — Fingir que ouve:** diz \"uhum\" sem processar.\n- **Nível 3 — Escuta seletiva:** ouve só o que interessa.\n- **Nível 4 — Escuta atenta:** processa o que está sendo dito.\n- **Nível 5 — Escuta empática:** entende não só o que está sendo dito, mas como a pessoa está se sentindo ao dizer. O varejo opera no nível 5.","tipo":"texto"},{"titulo":"Técnicas de escuta ativa","corpo":"- **Parafraseamento:** \"Então se eu entendi bem, você está buscando algo durável que não exija muito cuidado especial, certo?\"\n- **Perguntas de aprofundamento:** \"Você mencionou que o último não aguentou muito. O que especificamente aconteceu?\"\n- **Validação emocional:** \"Faz todo sentido querer ter certeza antes de investir nisso.\"\n- **Silêncio estratégico:** depois de uma pergunta importante, fique em silêncio. O cliente preencherá o espaço com informação valiosa.","tipo":"texto"},{"titulo":"Perguntas: a ferramenta mais poderosa do vendedor","corpo":"Neil Rackham, em estudo com 35.000 transações em 27 países, descobriu que os melhores vendedores fazem mais perguntas — e perguntas melhores.","tipo":"texto"},{"titulo":"Tipos de perguntas","corpo":"- **Abertas:** \"O que você está buscando pra essa ocasião?\"\n- **Fechadas:** \"Você precisa para essa semana, certo?\"\n- **De investigação:** \"Você mencionou durabilidade — por quê isso é tão importante pra você?\"\n- **Hipotéticas:** \"Imagina você usando isso na viagem que você mencionou — como seria?\"\n- **De implicação:** \"Se você não resolver isso agora, o que acontece?\"","tipo":"texto"},{"titulo":"Sequência de perguntas para o varejo","corpo":"- \"Você já conhece nossa linha ou está vendo pela primeira vez?\"\n- \"O que você está buscando especificamente?\"\n- \"Pra que ocasião/situação seria?\"\n- \"O que é mais importante pra você: preço, durabilidade, design?\"\n- \"Baseado no que você me disse, o modelo X parece ideal. Faz sentido pra você?\"","tipo":"texto"},{"titulo":"Storytelling: vender com histórias","corpo":"O cérebro humano é programado para histórias. Quando ouvimos uma narrativa, nosso cérebro libera oxitocina — o hormônio da confiança. **Dados informam. Histórias vendem.**","tipo":"texto"},{"titulo":"A estrutura da história de venda","corpo":"- **Personagem** — com quem o cliente se identifica\n- **Problema** — a situação antes do produto\n- **Solução** — o produto como virada\n- **Resultado** — a transformação\nExemplo: \"Semana passada atendi uma cliente que estava exatamente na sua situação... Ela levou esse aqui. Dois dias depois voltou pra me contar que recebeu um elogio da chefe — perguntou onde tinha comprado. Ela voltou hoje pra comprar o mesmo pra presentear a irmã.\"\nEssa história ativa: prova social, afinidade, emoção, autoridade — tudo de uma vez.","tipo":"texto"},{"titulo":"Linguagem de benefício vs. característica","corpo":"Nunca apresente características sem transformá-las em benefícios:\n- Característica — Benefício\n- Bateria de 48h — Você não precisa ficar preocupado com carregador durante a viagem\n- Tecido impermeável — Se pegar chuva, não vai estragar\n- Garantia de 2 anos — Qualquer problema nos próximos 2 anos, a gente resolve sem custo","tipo":"texto"},{"titulo":"Perguntas calibradas (Chris Voss)","corpo":"As melhores frases em negociação e atendimento são perguntas abertas que começam com \"como\" ou \"o que\". Mantêm o diálogo aberto e colocam o ônus de criar a solução no outro lado.\n- \"Como posso fazer isso funcionar para você?\"\n- \"O que tornaria esse valor mais confortável para você?\"\n- \"Como poderíamos chegar num acordo que funcionasse pros dois lados?\"","tipo":"texto"}]'::jsonb, 10),
('eafc27f8-76bb-43a3-8688-6cb10a036944', NULL, '3f849396-3fce-423a-b9c2-4de5d5c7f096', 'Atendimento premium', 'texto', NULL, NULL, 0, false, '[{"titulo":"A diferença entre atendimento comum e excepcional","corpo":"**Atendimento comum:** o cliente sai com o produto.\n**Atendimento excepcional:** o cliente sai com o produto E conta para alguém sobre a experiência.\nShep Hyken: \"O objetivo não é satisfazer o cliente. É surpreendê-lo.\"","tipo":"texto"},{"titulo":"O modelo de experiência em três níveis","corpo":"- **Nível 1 — Mínimo esperado:** produto disponível, preço correto, atendimento cordial. Se falhar aqui, o cliente reclama. Se acertar, não elogia — é o esperado.\n- **Nível 2 — Satisfação:** você entregou bem o esperado. Cliente sai satisfeito mas não necessariamente volta.\n- **Nível 3 — Encantamento:** você entregou algo que o cliente não esperava. É aqui que se constroem clientes fiéis e indicações espontâneas.","tipo":"texto"},{"titulo":"O Efeito Pico-Final (Daniel Kahneman)","corpo":"As pessoas não se lembram de toda uma experiência — elas se lembram do **pico emocional** e do **final**.","tipo":"texto"},{"titulo":"Como criar momentos de pico","corpo":"- Dar uma informação que o cliente não esperava e que é genuinamente útil\n- Resolver um problema que ele não pediu para você resolver\n- Fazer uma recomendação honesta que claramente não te favorece financeiramente\n- Lembrar de algo que ele mencionou em visita anterior","tipo":"texto"},{"titulo":"Como garantir um final forte","corpo":"O cliente vai lembrar do último momento do atendimento com a mesma intensidade dos melhores momentos. Garanta que a despedida seja:\n- **Personalizada** — use o nome do cliente\n- **Orientada para o futuro** — \"Qualquer dúvida, pode vir aqui ou me ligar\"\n- **Memorável** — algo que diferencia você de qualquer outro vendedor","tipo":"texto"},{"titulo":"Atendimento consultivo","corpo":"O atendimento consultivo é o oposto do atendimento transacional.\n**Transacional:** cliente chega, pergunta, você responde, ele compra ou não. Fim.\n**Consultivo:** você entende a situação completa, diagnostica a real necessidade, apresenta a solução ideal (que pode ser diferente do que ele pediu) e orienta sobre o uso.","tipo":"texto"},{"titulo":"Passos do atendimento consultivo","corpo":"- **Diagnóstico:** perguntas que revelam o contexto completo\n- **Escuta ativa:** captura de necessidades explícitas e ocultas\n- **Educação:** você compartilha conhecimento que o cliente não tem\n- **Recomendação personalizada:** não \"o melhor produto\", mas \"o melhor produto para você\"\n- **Orientação de uso:** você garante que o cliente vai usar bem o que comprou\n- **Follow-up:** verificação de satisfação após a compra","tipo":"texto"},{"titulo":"Gestão de expectativas","corpo":"**Regra: underpromise and overdeliver.** Prometer demais e entregar o esperado é pior do que prometer menos e surpreender.\nUm cliente que descobre algo que você \"esqueceu de mencionar\" após a compra vai transformar a satisfação em frustração — mesmo que o produto seja bom.","tipo":"texto"},{"titulo":"Hospitalidade no varejo","corpo":"Danny Meyer (Union Square Hospitality Group): \"O serviço é o que você faz tecnicamente. A hospitalidade é como a pessoa se sentiu sendo atendida por você.\"","tipo":"texto"},{"titulo":"Como humanizar o atendimento","corpo":"- Use o nome do cliente (aprenda no início da conversa)\n- Faça perguntas genuínas sobre a vida dele\n- Compartilhe sua opinião honesta como pessoa, não como vendedor\n- Admita quando não souber algo — e busque a resposta","tipo":"texto"},{"titulo":"O momento mais crítico para a fidelização","corpo":"É quando algo dá errado. Como você resolve um problema determina mais a fidelidade do cliente do que uma experiência perfeita.\nUm cliente que teve um problema resolvido de forma excepcional é mais fiel do que um cliente que nunca teve problemas.","tipo":"texto"}]'::jsonb, 10),
('d122abe6-d2f4-4f88-b5d7-1bf6ac578bfc', NULL, '812533b3-cf95-4d0e-8f47-aa52d10c43f7', 'Processo completo de venda', 'texto', NULL, NULL, 0, false, '[{"titulo":"A estrutura do processo","corpo":"A venda tem etapas. Pular etapas é o erro mais comum que leva ao travamento da venda ou à perda do cliente.\n**Preparação → Abordagem → Quebra de Gelo → Investigação → Apresentação → Demonstração → Negociação → Fechamento → Pós-venda → Indicação**","tipo":"texto"},{"titulo":"Preparação","corpo":"A maioria dos vendedores ignora essa etapa. Os melhores não.\n- **Conhecimento dos produtos:** saiba de cor as especificações, diferenciais e limitações de tudo que você vende.\n- **Conhecimento dos concorrentes:** o cliente provavelmente pesquisou na internet. Você também precisa saber — para comparar com honestidade.\n- **Estado mental:** vendedor desmotivado transmite energia negativa. O cliente sente.","tipo":"texto"},{"titulo":"Abordagem","corpo":"A abordagem define o tom de todo o atendimento. Uma abordagem errada coloca o cliente na defensiva.","tipo":"texto"},{"titulo":"Erros fatais de abordagem","corpo":"- \"Posso te ajudar?\" — resposta automática: \"não, obrigado.\"\n- Abordagem imediata demais — o cliente entrou há 10 segundos. O cérebro reptiliano ativa: perigo, pressão.\n- Ausência total — o cliente está esperando por atenção e ninguém aparece.","tipo":"texto"},{"titulo":"A abordagem de elite","corpo":"- **Cliente com objetivo definido:** \"Boa tarde! Pode me dizer o que está buscando que vou te levar direto.\"\n- **Cliente explorando:** \"Boa tarde, seja bem-vindo! Pode olhar à vontade. Qualquer dúvida, estou aqui.\" (aguarde o momento certo)\n- **Cliente que já conhece a loja:** \"Oi, voltou! Tem alguma coisa específica hoje ou está dando uma olhada?\"","tipo":"texto"},{"titulo":"Investigação (diagnóstico)","corpo":"**Esta é a etapa mais importante do processo.** O vendedor que mais vende não é o que mais fala — é o que mais pergunta e melhor escuta.","tipo":"texto"},{"titulo":"O que você precisa descobrir","corpo":"- Contexto: qual é a situação atual do cliente?\n- Necessidade real: o que ele precisa (pode ser diferente do que pediu)?\n- Critérios de decisão: o que é mais importante para ele?\n- Experiências anteriores: o que já usou? O que não funcionou?\n- Urgência: para quando precisa?\n- Quem decide: ele decide sozinho ou precisa consultar alguém?","tipo":"texto"},{"titulo":"Perguntas poderosas de investigação","corpo":"- \"Você já usou algo similar antes? Como foi a experiência?\"\n- \"O que é mais importante pra você nessa compra — preço, qualidade, durabilidade?\"\n- \"Seria pra você ou pra presentear?\"\n- \"Tem alguma coisa que você definitivamente quer evitar?\"","tipo":"texto"},{"titulo":"Apresentação da solução","corpo":"Após a investigação, você tem o mapa do cliente. Apresente a solução — não o produto.","tipo":"texto"},{"titulo":"Estrutura da apresentação perfeita","corpo":"- **Conexão com o diagnóstico:** \"Baseado no que você me contou...\"\n- **Apresentação do produto**\n- **Características → Benefícios:** para cada característica relevante, o benefício para aquele cliente específico\n- **Provas:** depoimentos, dados, certificações\n- **Validação:** \"Faz sentido com o que você está buscando?\"","tipo":"texto"},{"titulo":"Demonstração do produto","corpo":"Se existe a possibilidade de o cliente experimentar o produto, use isso. A demonstração ativa o Efeito de Dotação.\n- Entregue o produto na mão do cliente\n- Oriente o uso durante a demonstração\n- Aponte o que o cliente deve observar\n- Use perguntas durante: \"Sentiu a diferença no peso?\"","tipo":"texto"},{"titulo":"Sinais de compra (quando fechar)","corpo":"- Perguntas sobre logística: \"Tem entrega?\", \"Posso parcelar?\"\n- Visualização do uso: \"Daria pra usar com aquela outra peça minha...\"\n- Segura o produto sem largar\n- Pergunta sobre garantia\n- Concorda com tudo que você apresenta","tipo":"texto"},{"titulo":"Técnicas de fechamento","corpo":"- **Fechamento direto:** \"Posso separar esse pra você?\"\n- **Fechamento alternativo:** \"Você prefere levar em 3x ou pagar à vista?\" (pressupõe que vai levar)\n- **Fechamento por urgência real:** \"Esse modelo tem só dois em estoque. Se quiser garantir, é melhor decidir agora.\"\n- **Fechamento resumo:** resume os benefícios e pergunta: \"Está de acordo com o que você estava buscando?\"\n- **Fechamento condicional:** \"Se eu conseguir essa condição de parcelamento, a gente fecha?\"","tipo":"texto"},{"titulo":"Pós-venda","corpo":"A maioria dos vendedores encerra o atendimento quando o cliente paga. O vendedor de elite começa o relacionamento.\n- Confirme a decisão: \"Você vai adorar — escolheu muito bem.\"\n- Oriente o uso: \"Uma coisa importante: na primeira lavagem, coloque em água fria...\"\n- Informe sobre garantia e suporte\n- Plante o retorno: \"Quando você vir o resultado, me conta!\"\n- Abra a indicação: \"Se você gostar e tiver amigos que precisam de algo similar, pode mandar aqui.\"","tipo":"texto"},{"titulo":"Indicação: o mais valioso canal de venda","corpo":"Clientes indicados convertem 30% mais que clientes frios e têm Lifetime Value 16% maior.\nComo solicitar naturalmente (após o pós-venda, quando o cliente está em alto nível de satisfação):\n\"Fico feliz que tenha gostado! Você conhece alguém que também poderia se beneficiar de algo assim? Seria um prazer atendê-lo.\"","tipo":"texto"}]'::jsonb, 10),
('e5a9a073-974c-47dc-938f-e890cbda5f5c', NULL, '2271277b-a93f-4f6d-9ab0-c2105b8ebb99', 'Técnicas avançadas de venda', 'texto', NULL, NULL, 0, false, '[{"titulo":"SPIN Selling (Neil Rackham)","corpo":"A metodologia mais testada do mundo — 35.000 transações em 27 países. Os melhores vendedores fazem perguntas em uma sequência específica:\n- **S — Situação:** levanta informações sobre o contexto. \"Você já usa algum produto similar? Com que frequência vai usar?\"\n- **P — Problema:** revela dificuldades e insatisfações. \"O que você acha que poderia ser melhor no que usa hoje? Alguma vez já teve problema com [categoria]?\"\n- **I — Implicação:** expande o problema, mostra suas consequências. \"E quando esse problema acontece, qual é o impacto no seu dia a dia? Você calcula quanto isso te custa?\"\n- **N — Necessidade de Solução:** faz o cliente verbalizar os benefícios que quer. \"O que seria ideal pra você? Se você pudesse resolver isso de uma vez, como seria?\"\nQuando usar: em vendas de maior valor onde o cliente ainda não reconhece a extensão do problema.","tipo":"texto"},{"titulo":"Challenger Sale (Matthew Dixon e Brent Adamson)","corpo":"Pesquisa da CEB com 6.000 vendedores identificou que os melhores não são os mais relacionais — são os **Challengers: vendem ensinando algo que o cliente não sabe.**","tipo":"texto"},{"titulo":"Os três pilares","corpo":"- **Ensinar:** compartilhe um insight que o cliente não tem e que muda como ele vê o problema.\n- **Adaptar:** personalize a mensagem para o contexto específico do cliente.\n- **Assumir o controle:** não tenha medo de direcionar a conversa.\nNo varejo: \"Posso te contar algo que a maioria das pessoas não sabe sobre esse tipo de produto? A maioria compra focando no preço e depois gasta o dobro em manutenção. O que eu recomendo é avaliar assim...\"\nVocê educou, se diferenciou e assumiu o papel de autoridade — tudo em uma frase.","tipo":"texto"},{"titulo":"AIDA — a jornada de compra","corpo":"Modelo clássico que mapeia o caminho do cliente:\n- **A — Atenção:** o cliente nota você e o produto\n- **I — Interesse:** o cliente quer saber mais\n- **D — Desejo:** o cliente quer ter o produto\n- **A — Ação:** o cliente compra\nSe travar em alguma fase, identifique onde e aplique a técnica correta.","tipo":"texto"},{"titulo":"Venda por Valor (Value Selling)","corpo":"Toda negociação de preço é uma negociação de valor percebido.","tipo":"texto"},{"titulo":"Fórmula","corpo":"- Valor percebido > Preço = venda fácil\n- Valor percebido = Preço = venda possível\n- Valor percebido < Preço = sem desconto não fecha\n**Aumentar o valor percebido é infinitamente mais eficaz do que baixar o preço.**","tipo":"texto"},{"titulo":"Como calcular e apresentar valor","corpo":"- **Custo por dia:** R$300 ÷ 3 anos ÷ 365 dias = R$0,27/dia\n- **Custo comparativo:** R$300 de uma vez vs. R$150 de um inferior que dura 1 ano = mais barato pagar o dobro uma vez\n- **Custo de não comprar:** quanto vai custar o problema não resolvido?","tipo":"texto"},{"titulo":"Upsell e Cross-sell","corpo":"","tipo":"texto"},{"titulo":"Upsell — versão superior","corpo":"**Regra de ouro:** só faça sentido se o produto superior genuinamente atende melhor às necessidades declaradas do cliente.\n\"Você mencionou que vai usar com frequência. Nesse caso, o modelo superior tem a sola reforçada que vai durar o dobro do tempo — por apenas R$80 a mais. Para o uso que você descreveu, vale muito a pena.\"","tipo":"texto"},{"titulo":"Cross-sell — produto complementar","corpo":"**Regra de ouro:** apresente quando o produto complementar agrega valor real, não para bater meta.\n\"Já que você vai levar esse, um item que faz toda diferença junto é [produto X] — porque [benefício concreto]. Tem clientes que compram os dois sempre juntos por isso.\"","tipo":"texto"},{"titulo":"Estratégias de upsell por situação","corpo":"- **Cliente escolheu o produto mais barato:** \"Esse aqui funciona muito bem. Mas por R$[X] a mais, o modelo acima tem [diferencial relevante]. Para o uso que você mencionou, pode valer muito a pena.\"\n- **Cliente já decidiu e está satisfeito:** \"Perfeito! Antes de ir, posso te mostrar uma coisa que complementa muito bem esse?\"\n- **Cliente em dúvida entre dois:** \"Os dois são ótimos. A diferença principal é [diferencial real]. Se for usar [situação A], o superior vale. Se for [situação B], o básico resolve.\"","tipo":"texto"},{"titulo":"Geração de desejo antes do fechamento","corpo":"Entre a demonstração e o fechamento existe um momento crítico onde você precisa amplificar o desejo.","tipo":"texto"},{"titulo":"Técnicas","corpo":"- **Visualização futura:** \"Imagina você chegando na reunião com essa pasta — transmite exatamente o profissionalismo que você descreveu querer.\"\n- **Contraste:** \"O que você está usando hoje tem [problema X]. Com esse, você vai ter [benefício Y] todo dia.\"\n- **Custo da inação:** \"Você vai continuar com esse problema por mais tempo. Esse produto resolve isso de uma vez.\"","tipo":"texto"}]'::jsonb, 10),
('42794648-e053-4450-b7b2-d7c36bbee0b7', NULL, '66c828f5-6ced-4fc4-bf3d-f83a7d60271d', 'Negociação', 'texto', NULL, NULL, 0, false, '[{"titulo":"Preparação: a batalha é ganha antes de começar","corpo":"Sun Tzu: \"A batalha é ganha antes de ser travada.\"\nAntes de qualquer negociação, defina:\n- **Seu ponto ideal:** o que você quer obter idealmente\n- **Seu BATNA:** qual é o mínimo aceitável para você?\n- **Sua ZOPA:** a zona onde o acordo é possível para ambos\n- **O que você está disposto a ceder** e o que não está","tipo":"texto"},{"titulo":"BATNA — Best Alternative to a Negotiated Agreement","corpo":"É o que você vai fazer SE a negociação não fechar. Quanto melhor seu BATNA, mais poder você tem.\nPara um vendedor de varejo, um BATNA forte significa:\n- Outro cliente interessado no mesmo produto\n- A certeza de que o produto tem grande demanda\n- A confiança de que seu preço é justo e você não precisa descontar\nQuando você tem BATNA forte, negociação fica mais fácil porque você não \"precisa\" de cada venda individualmente.","tipo":"texto"},{"titulo":"ZOPA — Zone of Possible Agreement","corpo":"A faixa onde vendedor e comprador conseguem fechar um acordo. Se as expectativas de ambos não se sobrepõem, não existe zona de acordo e a negociação não vai fechar.","tipo":"texto"},{"titulo":"Ancoragem","corpo":"O primeiro número numa negociação serve de âncora para todos os números seguintes.\n**Regra: sempre que possível, ancore primeiro.**\n\"Esse produto está R$350.\" → Você ancorou em 350. Agora, qualquer proposta do cliente parte de 350. Um desconto para R$320 vai parecer uma concessão generosa.\nSe o cliente ancorar primeiro: \"Quanto você me dá por R$250?\" — agora a âncora é 250, e qualquer valor acima parece caro para ele.","tipo":"texto"},{"titulo":"Concessões: como dar sem perder","corpo":"**Nunca conceda sem receber algo em troca.** Uma concessão unilateral não tem valor percebido — o cliente acha que o preço original era mentira.","tipo":"texto"},{"titulo":"Técnica da concessão condicional","corpo":"- \"Se você fechar agora, consigo fazer R$290.\"\n- \"Se você levar os dois, consigo melhorar o valor.\"\n- \"Se pagar à vista, consigo ver uma condição especial.\"","tipo":"texto"},{"titulo":"Regras das concessões","corpo":"- **Faça concessões decrescentes:** a primeira é maior, as seguintes menores. Isso sinaliza que você está chegando no limite.\n- **Nunca conceda na mesma velocidade do cliente:** demore um pouco antes de cada concessão.\n- **Valorize cada concessão:** \"Vou ver o que posso fazer... [pausa] ...consegui R$280, mas é o máximo que consigo.\"","tipo":"texto"},{"titulo":"Negociação ganha-ganha (Chris Voss)","corpo":"Ex-negociador do FBI: \"A melhor negociação é aquela onde os dois lados saem sentindo que ganharam.\"","tipo":"texto"},{"titulo":"Como criar valor em vez de dividir","corpo":"Em vez de discutir somente preço, expanda o que está em discussão:\n- Condições de parcelamento\n- Produtos adicionais incluídos\n- Benefícios extras (embrulho, entrega, orientação de uso)\n- Prazo de pagamento\nQuando você expande as variáveis, existe mais espaço para criar valor sem sacrificar preço.","tipo":"texto"},{"titulo":"Linguagem em negociações","corpo":"","tipo":"texto"},{"titulo":"Perguntas calibradas","corpo":"As melhores frases em negociação são perguntas abertas que começam com \"como\" ou \"o que\". Por quê são poderosas: mantêm o diálogo aberto, colocam o ônus de criar a solução no outro lado e não revelam sua posição.\n- \"Como posso fazer isso funcionar para você?\"\n- \"O que tornaria esse valor mais confortável para você?\"\n- \"Como poderíamos chegar num acordo que funcionasse pros dois lados?\"","tipo":"texto"},{"titulo":"A técnica do espelho (Mirroring)","corpo":"Repita as últimas 2-3 palavras do que o cliente disse, com entonação curiosa. Isso faz o cliente continuar falando e revelar mais informação.\nCliente: \"Achei o preço um pouco salgado...\" Você: \"...um pouco salgado?\" Cliente: \"É, porque eu vi em outro lugar por menos...\"\nAgora você tem a informação real: o cliente pesquisou o concorrente. Pode trabalhar com isso.","tipo":"texto"},{"titulo":"Simulações","corpo":"**Situação 1 — Cliente pede preço muito abaixo:**\nCliente: \"Você não faz por R$200?\"\n❌ Vendedor mediano: \"Esse é o preço mesmo, não tem desconto.\" (fecha a porta)\n✓ Vendedor de elite: \"Posso ver o que consigo fazer. Mas antes de falar de valor, me conta — o que especificamente te fez pensar em R$200? Você viu esse produto por esse preço em outro lugar?\" (descobre a âncora do cliente antes de qualquer movimento)\n**Situação 2 — \"Está caro\":**\n✓ Vendedor de elite: \"Entendo. Me ajuda a entender — está caro em relação a quê? Em relação ao orçamento que você tinha em mente, ou em relação a produtos similares que você viu?\" (a resposta revela se é problema de valor percebido ou de orçamento real)","tipo":"texto"}]'::jsonb, 10),
('4b407a7e-9e9d-433d-bc6d-32e5959dbac4', NULL, 'c90081cc-85b6-4052-8812-f24e2959d6d4', 'Tratamento de objeções', 'texto', NULL, NULL, 0, false, '[{"titulo":"A verdade sobre objeções","corpo":"**Objeção não é rejeição. É pedido de mais informação.**\nQuando um cliente levanta uma objeção, ele está dizendo: \"Ainda não me convenceu completamente. Me dê mais.\"\nO vendedor que tem medo de objeções encolhe. O vendedor de elite fica animado — porque sabe que objeção é sinal de interesse.","tipo":"texto"},{"titulo":"Estrutura universal para tratamento de objeções","corpo":"**Acolha → Explore → Responda → Confirme**\n- **Acolha:** valide a objeção sem concordar com ela\n- **Explore:** entenda a objeção real (muitas vezes não é o que parece)\n- **Responda:** com argumento de valor, não de preço\n- **Confirme:** verifique se a objeção foi resolvida","tipo":"texto"},{"titulo":"Objeção de preço: \"Está caro\"","corpo":"Antes de responder, entenda: é objeção de **preço** (o cliente não tem o dinheiro) ou de **valor percebido** (o cliente tem o dinheiro mas acha que não vale)?\n**Se for valor percebido (mais comum):** \"Entendo que o valor pode parecer alto. Me deixa mostrar o que está incluído nesse preço que a maioria das pessoas não sabe... Quando você olha assim, o custo por dia fica em R$0,50. Menos que um café. E você vai usar isso todos os dias por anos.\"\n**Se for orçamento real:** \"Entendo. Me conta — quanto você tinha em mente? [...] Dentro desse valor, tenho [opção X] que vai atender bem [necessidade principal declarada].\"\nNão ofereça desconto como primeira resposta. Reforce o valor primeiro.","tipo":"texto"},{"titulo":"\"Vou pensar\"","corpo":"Esta é a objeção mais comum e a mais mal tratada. \"Vou pensar\" raramente significa \"vou pensar\". Significa:\n- Não vi valor suficiente para decidir agora\n- Tenho medo de tomar a decisão errada\n- Quero pesquisar a concorrência\n- Me sinto pressionado e preciso de espaço\n❌ Resposta errada: \"Claro, fique à vontade\" (e o cliente some para sempre).\n✓ Resposta de elite: \"Claro, faz todo sentido querer pensar. Me conta — tem alguma coisa específica que você quer avaliar melhor? Porque se tiver alguma dúvida que eu não esclareci bem, prefiro resolver agora do que deixar você com dúvida.\"\n**Se o cliente disser que quer pesquisar:** \"Perfeito. Posso te contar em que você deve prestar atenção ao comparar — algumas coisas que parecem iguais têm diferenças importantes...\"","tipo":"texto"},{"titulo":"\"Preciso falar com meu marido/minha esposa\"","corpo":"Esta objeção tem camadas — pode ser real ou uma desculpa para não decidir.\n✓ \"Claro, imagino que vocês decidem juntos. Me conta — você já está convencida de que esse é o produto certo, e o que falta é alinhar com ele? Ou ainda tem dúvidas que eu poderia esclarecer antes?\"\n✓ Se ela está convencida: \"O que ele vai querer saber? Me conta que aí você já vai chegar com os argumentos todos.\"","tipo":"texto"},{"titulo":"\"Não conheço essa marca\"","corpo":"✓ \"Entendo. É natural ter mais confiança em marcas que você já conhece. Posso te contar o que essa marca tem de diferente? [Fatos sobre a marca.] E posso te dizer que trabalho aqui há [tempo] e tenho um histórico muito positivo com essa linha — nunca tive problema de devolução por qualidade.\"","tipo":"texto"},{"titulo":"\"Não preciso disso agora\"","corpo":"✓ \"Entendo. Me conta — o que está te fazendo pensar que não precisa agora? Porque às vezes a gente posterga coisas que depois lamenta.\"","tipo":"texto"},{"titulo":"Banco de respostas rápidas","corpo":"- Objeção — Abertura de resposta\n- \"Está caro\" — \"Entendo. Me conta — caro em relação a quê?\"\n- \"Vou pensar\" — \"Claro. Tem alguma dúvida específica que ficou?\"\n- \"Não tenho dinheiro\" — \"Entendo. Quanto você tinha em mente?\"\n- \"Vi mais barato\" — \"Onde você viu? Me conta que posso te ajudar a comparar.\"\n- \"Não gostei do modelo\" — \"O que especificamente não te agradou? Tenho outras opções.\"\n- \"Minha esposa não vai gostar\" — \"O que ela costuma valorizar mais nesse tipo de produto?\"\n- \"Qualidade não presta\" — \"Você já usou essa marca antes ou é uma percepção geral?\"\n- \"Compro depois\" — \"Tem alguma razão específica pra deixar pra depois?\"","tipo":"texto"}]'::jsonb, 10),
('ce880fad-0e4e-4e3a-bee4-295de1b7dc7e', NULL, '4670e45b-76a1-4129-9058-92e07ea3a1f0', 'Atendimento a clientes difíceis', 'texto', NULL, NULL, 0, false, '[{"titulo":"A mentalidade correta","corpo":"**Não existe cliente difícil.** Existe cliente com necessidade não atendida, expectativa frustrada, medo não reconhecido ou situação pessoal que está impactando o comportamento.\nQuando você muda de \"esse cliente é difícil\" para \"esse cliente está passando por algo e precisa de uma abordagem diferente\", você tira o julgamento e coloca o problema — que você pode resolver.","tipo":"texto"},{"titulo":"Cliente nervoso / agressivo","corpo":"Ele foi prejudicado (ou sente que foi). A raiva é uma resposta a uma ameaça percebida — real ou imaginada.","tipo":"texto"},{"titulo":"O que NÃO fazer","corpo":"- Confrontar ou argumentar enquanto ele está emocional\n- Ser frio ou burocrático\n- Ficar na defensiva\n- Dizer \"calma\" — isso piora a situação","tipo":"texto"},{"titulo":"O que fazer","corpo":"- **Contenção emocional:** deixe-o falar. Não interrompa. Não argumente. Só escute.\n- **Validação:** reconheça o sentimento, não necessariamente o conteúdo. \"Entendo que você está muito frustrado com isso. Se eu estivesse na sua situação, também estaria.\"\n- **Mudança de estado:** quando a emoção baixar, redirecione para a solução. \"Agora me conta exatamente o que aconteceu. Quero entender tudo para resolver da melhor forma possível.\"\n- **Ação:** apresente uma solução concreta e rápida.\nPrincípio Chris Voss: \"A emoção precisa ser nomeada antes de poder ser resolvida.\" Nomeie o sentimento do cliente — isso ativa a parte racional do cérebro e reduz a intensidade emocional.","tipo":"texto"},{"titulo":"Cliente indeciso","corpo":"Medo de tomar a decisão errada. Pode ser perfil Estável ou Analítico.","tipo":"texto"},{"titulo":"O que fazer","corpo":"- **Reduza as opções:** apresente no máximo duas — e recomende claramente. \"Baseado no que você me descreveu, esses dois atendem bem. Mas se eu fosse você, levaria o segundo — por [razão específica].\"\n- **Reduza o risco percebido:** \"Qualquer problema, você pode trazer de volta — temos política de troca sem burocracia.\"\n- **Use prova social:** \"A maioria das pessoas que está na sua situação escolhe esse.\"","tipo":"texto"},{"titulo":"Cliente desconfiado","corpo":"Ele já foi enganado antes. A desconfiança é proteção.","tipo":"texto"},{"titulo":"O que fazer","corpo":"- **Valide a desconfiança:** \"Faz todo sentido ser cuidadoso. Existem muitas opções no mercado e nem todas são o que prometem.\"\n- **Seja transparente:** mostre limitações do produto antes que ele pergunte. Quando o vendedor aponta os pontos negativos, o cliente conclui que você é honesto.\n- **Use evidências:** certificações, depoimentos reais, dados verificáveis.","tipo":"texto"},{"titulo":"Cliente apressado","corpo":"Ele tem pouco tempo. Não é hostilidade — é necessidade.","tipo":"texto"},{"titulo":"O que fazer","corpo":"- **Corresponda à velocidade:** \"Vou direto ao ponto então: você está buscando [X], o melhor custo-benefício aqui é esse, por [razão]. Posso te mostrar em 2 minutos?\"\n- **Facilite a decisão:** \"Posso embrulhar enquanto você finaliza? Assim agiliza.\"","tipo":"texto"},{"titulo":"Cliente que \"só está dando uma olhada\"","corpo":"Ele não quer ser pressionado. Provavelmente foi abordado de forma invasiva antes.","tipo":"texto"},{"titulo":"O que fazer","corpo":"- Não pressione: \"Claro, pode ficar à vontade.\"\n- Aguarde o sinal de interesse natural.\n- Engaje pelo produto: \"Esse produto chegou essa semana — posso te contar uma coisa interessante sobre ele?\"\n- Quando ele parar em algo: \"Você parou nesse aqui por um motivo — tem alguma coisa que te chamou atenção?\"","tipo":"texto"},{"titulo":"Cliente que reclama de tudo","corpo":"Pode ser perfil naturalmente crítico (Analítico) ou alguém que teve experiências ruins e construiu uma postura defensiva.","tipo":"texto"},{"titulo":"O que fazer","corpo":"- **Escute sem defender:** cada reclamação é uma percepção. Não argumente — valide.\n- **Use a reclamação como diferencial:** \"Justamente por isso esse produto funciona diferente. O que você está descrevendo é exatamente o problema que esse aqui resolve.\"\n- **Mostre que você está do lado dele:** \"Você está certo em ser criterioso. Deixa eu te mostrar por que esse aqui vai superar essa expectativa.\"","tipo":"texto"},{"titulo":"Reframe mental para cada tipo","corpo":"- Cliente nervoso = \"Esse cliente foi prejudicado e precisa ser ouvido.\"\n- Cliente indeciso = \"Esse cliente tem medo de errar e precisa de segurança.\"\n- Cliente desconfiado = \"Esse cliente foi enganado antes e precisa de transparência.\"\n- Cliente apressado = \"Esse cliente tem pouco tempo e precisa de objetividade.\"","tipo":"texto"}]'::jsonb, 10),
('c29c49d8-269f-4e07-a4ef-f44f80d38177', NULL, '5261fa9b-4648-4c6b-9277-a564e3f1c5c9', 'Fidelização de clientes', 'texto', NULL, NULL, 0, false, '[{"titulo":"Por que fidelização é o maior ROI do varejo","corpo":"Vender para cliente novo custa 5-7x mais que vender para cliente existente. Um cliente que compra 3x tem probabilidade 54% maior de comprar uma 4ª vez.\n**LTV — Lifetime Value:** o valor total que um cliente gera durante toda a relação com a loja. Um cliente que compra R$200/mês por 5 anos tem LTV de R$12.000 — não de R$200.\nQuando você muda a unidade de análise de \"essa venda\" para \"esse cliente ao longo dos anos\", tudo muda.","tipo":"texto"},{"titulo":"A pirâmide da fidelização","corpo":"- **Satisfação:** o cliente não ficou insatisfeito. Mínimo para não perder. Não gera fidelidade.\n- **Lealdade:** o cliente volta quando precisa. Bom. Mas ainda compra do concorrente.\n- **Encantamento:** o cliente fala de você para os outros. Aqui começa o crescimento orgânico.\n- **Advocacy:** o cliente defende a loja em conversas e indica ativamente. Esse é o objetivo.\nSatisfação não é suficiente. Encantar é o padrão mínimo para crescer.","tipo":"texto"},{"titulo":"Customer Experience (CX)","corpo":"CX é a soma de todas as interações do cliente com a loja — antes, durante e depois da compra.","tipo":"texto"},{"titulo":"Os momentos que mais importam","corpo":"- **Primeira impressão:** os primeiros 30 segundos definem o tom. Ambiente, abordagem, sensação de acolhimento.\n- **O momento de dúvida:** quando o cliente estava prestes a desistir e o vendedor salvou a venda com a informação certa.\n- **O pós-compra:** o que acontece depois da venda. Embrulho, orientação de uso, follow-up.\nEfeito Pico-Final (Nobel Daniel Kahneman): a memória de uma experiência é definida pelo pico emocional e pelo momento final — não pela média. Garanta que o pico seja extraordinário e que o final seja excelente.","tipo":"texto"},{"titulo":"Customer Success no varejo","corpo":"CS adaptado para lojas físicas significa garantir que o cliente tenha sucesso usando o que comprou.","tipo":"texto"},{"titulo":"Práticas concretas","corpo":"- **Orientação de uso no momento da venda:** \"Esse produto funciona melhor se você...\"\n- **Follow-up pós-compra:** uma mensagem 3-7 dias depois: \"Como está sendo a experiência com [produto]?\"\n- **Antecipação de problemas:** \"Um detalhe importante que muita gente não sabe sobre esse produto é...\"","tipo":"texto"},{"titulo":"Sistema de encantamento — os 5 pontos de contato","corpo":"- Ponto — Ação concreta\n- Recepção — Nome + sorriso + espaço (não pressionar)\n- Descoberta — Perguntas abertas para entender o contexto real\n- Apresentação — História do produto, não lista de atributos\n- Fechamento — Confirmação de que resolveu o problema certo\n- Pós-venda — Orientação + follow-up + abertura para retorno","tipo":"texto"},{"titulo":"Programas de fidelidade — o que funciona","corpo":"Programas de pontos funcionam menos do que relacionamento genuíno. O que fideliza de verdade:\n- **Reconhecimento pessoal:** lembrar o nome, o que comprou antes, o que falou na última visita.\n- **Acesso antecipado:** avisar antes de promoções e novidades.\n- **Atenção especial:** tratar como VIP sem exigir nada em troca.\nUm vendedor que lembra o nome do cliente e pergunta sobre um produto que ele comprou 3 meses atrás faz mais pela fidelização do que qualquer programa de pontos.","tipo":"texto"}]'::jsonb, 10),
('7e49c818-8e16-41dd-b15e-90d0a182c692', NULL, '911e3c7b-2e94-40e7-b2d9-9d92bbed5517', 'Inteligência comercial', 'texto', NULL, NULL, 0, false, '[{"titulo":"As métricas que todo vendedor deve conhecer","corpo":"Você não pode melhorar o que não mede. As métricas corretas revelam onde exatamente o processo de venda está falhando.","tipo":"texto"},{"titulo":"Taxa de conversão","corpo":"**Definição:** % de clientes que entram na loja e compram algo. **Fórmula:** (vendas / visitantes) × 100 **Benchmark varejo:** 20-30% é saudável. Abaixo de 15% indica problema de atendimento ou produto. **Como melhorar:** abordagem mais rápida, qualificação melhor, oferta mais relevante.","tipo":"texto"},{"titulo":"Ticket médio","corpo":"**Definição:** valor médio de cada venda. **Fórmula:** faturamento total / número de vendas **Como melhorar:** upsell, cross-sell, apresentar versões premium antes das básicas.","tipo":"texto"},{"titulo":"Itens por venda","corpo":"Quantos produtos por transação. Cada item adicional por venda tem custo marginal zero de captação — o cliente já está na loja. **Como melhorar:** sugestões complementares naturais, não forçadas.","tipo":"texto"},{"titulo":"Taxa de retorno","corpo":"% de clientes que voltam em 90 dias. Indicador direto de fidelização. **Como melhorar:** pós-venda ativo, follow-up, experiência que supera expectativa.","tipo":"texto"},{"titulo":"Visual Merchandising","corpo":"O arranjo físico da loja influencia diretamente as vendas. Não é estética — é psicologia aplicada.","tipo":"texto"},{"titulo":"Princípios","corpo":"- **Zona de entrada:** os primeiros metros são de descompressão. Não coloque produtos principais aqui — o cliente ainda está ajustando ao ambiente.\n- **Zona quente:** o caminho natural do olhar ao entrar. Produtos de maior margem ou novidades devem estar aqui.\n- **Nível dos olhos = nível das vendas:** produtos na altura dos olhos vendem mais. Use para produtos de alta margem.\n- **Cross-merchandising:** colocar produtos complementares juntos (ex: celular + capinha + película no mesmo espaço).\n- **Escassez visual:** 3-5 unidades de um produto visíveis vendem mais que prateleira cheia. Cheia parece \"não vendeu\".","tipo":"texto"},{"titulo":"Análise da jornada do cliente","corpo":"Mapeie o que acontece em cada etapa da visita — não para controlar, mas para identificar onde clientes saem sem comprar.","tipo":"texto"},{"titulo":"Pontos de abandono comuns","corpo":"- **Não abordado nos primeiros 2 minutos:** cliente se sente ignorado e sai.\n- **Abordado mas com script genérico:** \"posso ajudar?\" → \"estou só olhando\" → fim.\n- **Apresentou produto, mas não identificou necessidade:** produto certo, cliente errado.\n- **Chegou no preço cedo demais:** antes de criar valor, preço parece sempre alto.\n- **Não fechou com pergunta de comprometimento:** ficou esperando o cliente decidir sozinho.","tipo":"texto"},{"titulo":"Framework de melhoria contínua — PDCA para vendas","corpo":"- Fase — No varejo\n- Plan (Planejar) — Identificar métricas fracas e hipótese de causa\n- Do (Fazer) — Testar abordagem nova por 1-2 semanas\n- Check (Checar) — Comparar métricas antes e depois\n- Act (Agir) — Padronizar se funcionou, ou reformular hipótese","tipo":"texto"},{"titulo":"Exemplo prático","corpo":"**Problema identificado:** taxa de conversão caiu de 25% para 18%. **Hipótese:** abordagem muito tarde (clientes esperando mais de 3 min). **Teste:** nova regra: abordar em menos de 60 segundos por 2 semanas. **Resultado:** conversão volta para 23%. **Ação:** padronizar abordagem rápida para toda equipe.","tipo":"texto"}]'::jsonb, 10),
('49903a39-5dba-4367-8949-13f8cc6bc9b1', NULL, '460cdf99-8388-43fc-9525-f9006329d6c4', 'Liderança comercial', 'texto', NULL, NULL, 0, false, '[{"titulo":"Os 4 papéis do líder de vendas","corpo":"Líderes comerciais de elite não apenas gerenciam resultados — desenvolvem pessoas. Existem quatro papéis distintos, e o erro mais comum é ficar preso em apenas um.","tipo":"texto"},{"titulo":"1. Estrategista","corpo":"Define onde a equipe vai, como vai chegar lá e como vai medir o progresso. Define metas, prioridades e alocação de esforço.","tipo":"texto"},{"titulo":"2. Treinador (Coach)","corpo":"Desenvolve as habilidades individuais de cada membro. Observa atendimentos, dá feedback específico, cria planos de desenvolvimento personalizados.","tipo":"texto"},{"titulo":"3. Motivador","corpo":"Mantém energia e comprometimento da equipe, especialmente em períodos difíceis. Reconhece publicamente, cria senso de propósito, remove obstáculos.","tipo":"texto"},{"titulo":"4. Gestor operacional","corpo":"Garante que processos funcionem: escala, cobertura, reposição, relatórios. Necessário, mas insuficiente como único papel.\nLíderes que ficam apenas no papel 4 gerenciam bem mas não desenvolvem time. O papel 2 (coach) é o mais subutilizado e o que tem maior impacto no longo prazo.","tipo":"texto"},{"titulo":"Motivação — Daniel Pink: Drive","corpo":"Pink identificou 3 fatores de motivação intrínseca — que funcionam muito melhor que dinheiro e punição para tarefas que exigem criatividade e engajamento.","tipo":"texto"},{"titulo":"Autonomia","corpo":"Pessoas se engajam mais quando têm controle sobre o próprio trabalho. Para vendedores: deixar cada um desenvolver seu estilo próprio dentro dos princípios da empresa. Não microgerenciar scripts.","tipo":"texto"},{"titulo":"Maestria","corpo":"O desejo de ficar cada vez melhor em algo que importa. Para vendedores: criar trilhas claras de desenvolvimento, feedbacks que mostram evolução, desafios progressivos.","tipo":"texto"},{"titulo":"Propósito","corpo":"Saber que o trabalho tem impacto além do próprio salário. Para vendedores: conectar a venda ao impacto real na vida do cliente. \"Você não vende eletrônico. Você conecta pessoas a ferramentas que melhoram a vida delas.\"\nBônus e comissões são importantes — mas funcionam para tarefas mecânicas. Para o trabalho criativo e relacional de vender bem, autonomia + maestria + propósito são mais poderosos.","tipo":"texto"},{"titulo":"Feedback SBI — Situação, Comportamento, Impacto","corpo":"O modelo mais eficaz de feedback para equipes de vendas.\n- Elemento — Pergunta — Exemplo\n- Situação — Quando/onde aconteceu? — \"Ontem, no atendimento com o cliente das 15h...\"\n- Comportamento — O que você observou especificamente? — \"...você apresentou o preço antes de terminar de mostrar os benefícios...\"\n- Impacto — Qual foi o efeito concreto? — \"...e o cliente focou só no preço, o que dificultou o fechamento.\"\n**Feedback de melhoria:** \"O que você acha que poderia ter feito diferente nesse momento?\"\n**Por que funciona:** é específico (não \"você precisa melhorar\"), é descritivo (não julgamento), e conecta comportamento a resultado real.","tipo":"texto"},{"titulo":"Metas SMART para equipes de vendas","corpo":"- **S — Específica:** não \"vender mais\", mas \"aumentar ticket médio de R$280 para R$340\"\n- **M — Mensurável:** com número e unidade claros\n- **A — Atingível:** desafiadora mas dentro da realidade da equipe\n- **R — Relevante:** conectada à meta maior da loja\n- **T — Temporal:** com prazo definido (este mês, este trimestre)","tipo":"texto"},{"titulo":"Cultura de alta performance","corpo":"Cultura não é o que o líder fala — é o que o líder tolera.","tipo":"texto"},{"titulo":"Comportamentos que definem a cultura","corpo":"- O que acontece quando alguém chega atrasado? (Tolerância ou consequência?)\n- O que acontece quando alguém atinge a meta? (Reconhecimento ou silêncio?)\n- O que acontece quando alguém comete um erro? (Punição ou aprendizado?)\n- O que acontece quando alguém age diferente dos valores? (Correção imediata ou nada?)\nAs respostas a essas perguntas são a cultura real — não os valores no mural.","tipo":"texto"}]'::jsonb, 10),
('ac88acf9-01a7-46ca-80b4-0978791267fd', NULL, '48670c49-0aef-47ad-9032-0109fce78f99', 'Vendas aplicadas', 'texto', NULL, NULL, 0, false, '[{"titulo":"O roteiro base — estrutura de um atendimento de elite","corpo":"Não é um script rígido. É uma sequência de intenções. O vendedor de elite sabe em que fase está e o que precisa acontecer antes de avançar.","tipo":"texto"},{"titulo":"Fase 1 — Acolhimento (0-60 segundos)","corpo":"**Objetivo:** criar segurança psicológica. O cliente precisa sentir que não vai ser pressionado. **Como:** sorriso genuíno, dar espaço, cumprimentar sem assédio. **Erro:** \"posso ajudar?\" — resposta automática é \"não, obrigado\". **Melhor:** abordagem pelo produto — \"Esse aí chegou essa semana. Posso te contar algo interessante sobre ele?\"","tipo":"texto"},{"titulo":"Fase 2 — Descoberta (60s-3 min)","corpo":"**Objetivo:** entender a necessidade real, não a declarada. **Como:** perguntas abertas, escuta ativa, silêncio produtivo. **Chave:** deixar o cliente falar mais do que você. Proporção 70-30 (cliente fala 70%).","tipo":"texto"},{"titulo":"Fase 3 — Apresentação (3-8 min)","corpo":"**Objetivo:** apresentar a solução certa, não todos os produtos. **Como:** máximo 2-3 opções, sempre conectando ao que o cliente disse na descoberta. **Formato:** benefício (não atributo) + prova + pergunta de validação.","tipo":"texto"},{"titulo":"Fase 4 — Objeções","corpo":"**Objetivo:** tratar, não contornar. **Como:** acolher → explorar → responder → confirmar resolução.","tipo":"texto"},{"titulo":"Fase 5 — Fechamento","corpo":"**Objetivo:** ajudar o cliente a tomar uma decisão que já é a certa para ele. **Como:** perguntas de comprometimento diretas, mas sem pressão. **Sinal de compra:** quando o cliente faz perguntas de detalhes (prazo, entrega, modos de pagamento) — está pronto. **Fechamento direto:** \"Vou embalar esse para você.\" **Fechamento alternativo:** \"Você prefere pagar no cartão ou à vista?\"","tipo":"texto"},{"titulo":"Fase 6 — Pós-venda","corpo":"**Objetivo:** garantir que a experiência foi boa e abrir caminho para o retorno. **Como:** orientação de uso, agradecimento genuíno, convite para voltar.","tipo":"texto"},{"titulo":"Estratégias de upsell por situação","corpo":"- Situação — Estratégia — Frase\n- Cliente escolheu versão básica — Âncora premium antes — \"Tenho esse aqui [premium] que é o top da linha. Posso te mostrar a diferença?\"\n- Cliente vai pagar e fechar — Cross-sell complementar — \"Tem uma coisa que combina perfeitamente com esse...\"\n- Cliente está animado com o produto — Garantia/proteção — \"Como você vai usar muito, tem uma proteção que vale a pena...\"\n- Cliente menciona outra pessoa — Venda adicional — \"Já que você vai dar de presente, tem opções que ficam muito bem em par...\"\n- Cliente voltou para trocar — Upgrade na troca — \"Já que está trocando, esse aqui tem um diferencial que o anterior não tinha...\"","tipo":"texto"},{"titulo":"Os 12 Princípios do Vendedor de Elite","corpo":"- **Você vende o que você é.** Autenticidade gera confiança. Técnica sem caráter é manipulação.\n- **Pergunte mais, fale menos.** Quem pergunta controla a conversa. Quem fala demais perde o fio do cliente.\n- **O cliente compra o resultado, não o produto.** Venda o futuro que o produto possibilita, não os atributos.\n- **Toda objeção é uma pergunta disfarçada.** Trate com curiosidade, não com medo.\n- **Preço nunca é o problema real.** É valor percebido insuficiente. Invista em valor primeiro.\n- **Urgência criada, não fabricada.** Urgência legítima (estoque real, promoção real) fecha. Urgência falsa destroça confiança.\n- **Silêncio é uma ferramenta.** Depois de apresentar um produto, cale-se e deixe o cliente processar.\n- **Consistência bate talento no longo prazo.** O vendedor que atende bem todos os dias bate o talentoso que é irregular.\n- **Relacionamento é ativo de longo prazo.** Cada cliente que você encanta bem hoje é uma fonte de indicações futuras.\n- **Você é responsável pelos seus resultados.** Nada de culpar a loja, o produto, o preço, o dia. O que está dentro do seu controle?\n- **A venda começa quando o cliente diz não.** Até lá, você estava só apresentando. Resiliência é o que separa os melhores.\n- **Aprenda algo novo sobre vendas toda semana.** O mercado muda. O cliente muda. O vendedor que para de aprender para de crescer.\nEsses 12 princípios são a síntese de tudo nessa formação. Voltará a eles sempre que precisar de norte.","tipo":"texto"}]'::jsonb, 10),
('e4a6ca23-edf1-4ffc-9698-b276e6f8df4e', NULL, '2d7b6e7a-6c66-40d1-9b6f-5263fe68aa26', 'Mentalidade B2B — O que muda no atacado', 'texto', NULL, NULL, 0, false, '[{"titulo":"O que muda no atacado","corpo":"- Varejo (B2C) — Atacado (B2B)\n- 1 decisão = 1 pessoa — 1 decisão = múltiplos aprovadores\n- Emoção domina — Lógica + ROI + risco\n- Ticket: R$50–R$500 — Ticket: R$2k–R$500k\n- Ciclo: minutos a horas — Ciclo: dias a semanas\n- Relacionamento é diferencial — Relacionamento é barreira de saída\n- 1 contato fecha — Múltiplos contatos para fechar","tipo":"texto"},{"titulo":"Os 3 papéis no processo de compra B2B","corpo":"- Papel — Quem é — O que importa — Como abordar\n- Usuário — Quem vai usar no dia a dia — Praticidade, qualidade, suporte — Mostre como facilita o trabalho dele\n- Influenciador — Gerente, comprador técnico — Especificações, comparativos, risco — Dados, ficha técnica, cases\n- Decisor — Dono, diretor, financeiro — ROI, prazo de retorno, risco financeiro — Foco total em número e resultado\n**Regra:** identifique quem é o decisor final e adapte a linguagem para o papel de quem está na frente.","tipo":"texto"},{"titulo":"O que o comprador de atacado realmente quer","corpo":"- **Certeza de entrega:** prazo cumprido é mais importante que preço\n- **Consistência de qualidade:** lote 1 = lote 50\n- **Parceiro, não fornecedor:** quem resolve problema é quem fica\n- **Facilidade operacional:** pedido fácil, nota certa, suporte ágil\n- **Crédito e condição:** prazo de pagamento é parte do produto","tipo":"texto"},{"titulo":"Por que compradores trocam de fornecedor","corpo":"- Motivo — % dos casos\n- Problema de atendimento / suporte — 68%\n- Sensação de não ser valorizado — 14%\n- Produto concorrente melhor — 9%\n- Preço — 9%\n**68% das perdas são por atendimento, não por produto ou preço.**","tipo":"texto"}]'::jsonb, 10),
('98f84ec7-8b27-4280-bd4b-b2b1c9c64616', NULL, '8fba103e-8852-46ac-9261-a860898f94b6', 'Perfil do Comprador B2B e Qualificação', 'texto', NULL, NULL, 0, false, '[{"titulo":"Os 5 tipos de comprador no atacado","corpo":"- Tipo — Comportamento — O que quer — Estratégia\n- Caçador de preço — Pesquisa tudo, decide por centavos — Menor custo total — Mostre custo total de posse — frete, ruptura, retrabalho\n- Fiel por comodidade — Compra do mesmo há anos — Zero fricção — Torne mudar ainda mais fácil do que ficar\n- Analítico — Planilha tudo, pede dados, demora — Segurança e comparativo — Dê dados, cases, certificações, projeto piloto\n- Construtor de relacionamento — Compra de quem conhece e confia — Parceria e confiança — Presença constante, atendimento personalizado\n- Estratégico — Compra alinhado com estratégia do negócio — Resultado de negócio — Linguagem de resultado: giro, margem, posicionamento","tipo":"texto"},{"titulo":"Qualificação — as perguntas que importam","corpo":"No atacado, **qualificar antes de propor** economiza semanas.\n- Dimensão — Pergunta\n- Volume — \"Qual o volume médio mensal que vocês trabalham nessa categoria?\"\n- Ciclo — \"Como é o processo de aprovação de novos fornecedores aqui?\"\n- Dor atual — \"O que você mudaria no fornecedor atual se pudesse?\"\n- Critério — \"Na hora de avaliar um novo fornecedor, o que é inegociável pra vocês?\"\n- Timing — \"Existe uma data ou evento que torna isso urgente?\"\n- Orçamento — \"Existe uma faixa de investimento definida ou isso está em aberto?\"","tipo":"texto"},{"titulo":"BANT adaptado ao atacado","corpo":"- Letra — Original — No atacado\n- B — Budget — Volume potencial + prazo de pagamento viável\n- A — Authority — Quem assina o pedido final\n- N — Need — Dor real com fornecedor atual + urgência\n- T — Timeline — Quando precisa receber + frequência de pedidos","tipo":"texto"},{"titulo":"Por que qualificar antes de propor","corpo":"Proposta sem qualificação = trabalho para o lixo. Você pode passar 3 dias montando uma proposta sofisticada para um cliente que não tem autonomia para aprovar, não tem o volume mínimo viável, ou já está comprometido com concorrente por contrato. 30 minutos de qualificação protege semanas de trabalho.","tipo":"texto"}]'::jsonb, 10),
('70dd4b2d-e087-4a23-9630-ea7772ba91e1', NULL, '8c8628c3-9cea-42d2-8d4d-93d6c05228c7', 'Proposta de Valor e ROI no Atacado', 'texto', NULL, NULL, 0, false, '[{"titulo":"A proposta que fecha vs. a que não fecha","corpo":"- Proposta que não fecha — Proposta que fecha\n- Tabela de preços genérica — Começa com a dor do cliente\n- Sem contextualização — Mostra entendimento do negócio dele\n- Igual à da concorrência — Propõe mix específico, não catálogo\n- Não mostra o ROI — Calcula retorno financeiro\n- Envia por e-mail e espera — Apresenta ao vivo e conduz próximo passo","tipo":"texto"},{"titulo":"Estrutura da proposta vencedora","corpo":"- **Contexto:** \"Com base na nossa conversa, entendemos que vocês buscam X e o problema atual é Y.\"\n- **Nossa solução:** mix recomendado especificamente para o negócio — não catálogo completo\n- **Diferencial:** o que nos separa dos outros fornecedores no que importa para este cliente\n- **Números:** custo por unidade, margem estimada do cliente, prazo de retorno do pedido mínimo\n- **Condições:** prazo de pagamento, entrega, pedido mínimo, política de troca\n- **Próximo passo:** data específica para retorno — nunca \"fica à vontade pra dar uma olhada\"","tipo":"texto"},{"titulo":"Linguagem de ROI — como falar com o decisor","corpo":"**Fórmula de margem bruta:**\n**Margem bruta = (Preço de venda − Custo) ÷ Preço de venda × 100**\n**Exemplo de apresentação com ROI:** \"Fiz o cálculo baseado no giro que você me informou. Se você comprar 200 unidades a R$18 e vender a R$35, você gera R$3.400 de margem bruta nesse lote. Com nosso prazo de 30 dias, você provavelmente já vendeu 60-70% antes de pagar.\"","tipo":"texto"},{"titulo":"Por que apresentar ao vivo supera envio por e-mail","corpo":"- Você controla o ritmo da apresentação\n- Trata objeções em tempo real — antes que o cliente decida sozinho\n- Define o próximo passo imediatamente — sem ficar aguardando retorno\n- Percebe o que gerou interesse (linguagem corporal, perguntas, silêncio)\n- Proposta por e-mail compete com 50 outros e-mails — apresentação ao vivo tem atenção total","tipo":"texto"}]'::jsonb, 10),
('a609fd85-692b-4398-bf64-1b5a4afe30ad', NULL, 'c66a26c7-6523-4a0f-b7d5-c8bad785dd24', 'Negociação no Atacado', 'texto', NULL, NULL, 0, false, '[{"titulo":"O desconto que mata sua margem","corpo":"**Desconto de 5% num produto com margem de 25% elimina 20% do seu lucro.**\nNunca dê desconto sem contrapartida.\n- Em vez de desconto puro — Ofereça em troca de algo\n- \"X% se fechar hoje\" — Volume mínimo maior, pedido imediato, prazo menor\n- \"Posso ver isso aqui\" — \"Se você dobrar o volume, consigo trabalhar melhor o preço\"\n- Condição especial — Exclusividade por região ou categoria","tipo":"texto"},{"titulo":"Táticas comuns de compradores B2B — e como responder","corpo":"- Tática do comprador — O que está fazendo — Sua resposta\n- \"O concorrente ofereceu X% menos\" — Ancoragem por preço externo — \"Entendo. Me conta — o produto é idêntico? Entrega, qualidade de lote e suporte entram no custo total.\"\n- \"Vai ter que melhorar bastante\" — Pressão sem âncora específica — \"Me diz onde precisa chegar — aí eu sei se consigo ou não, e o que precisaria em troca.\"\n- \"Preciso levar pra diretoria\" — Evasão ou processo real — \"Claro. O que a diretoria vai perguntar que posso te ajudar a responder agora?\"\n- [Silêncio após proposta] — Pressão psicológica — Fique em silêncio também. Quem fala primeiro cede primeiro.","tipo":"texto"},{"titulo":"Fechamento B2B — próximos passos concretos","corpo":"No B2B nunca \"feche\" — defina o próximo passo. Mesmo \"próxima reunião com o diretor\" é progresso mensurável.\n- Momento — Frase de próximo passo\n- Após apresentação — \"Quais são as próximas etapas do processo aí?\"\n- Aguardando aprovação — \"Posso ligar quarta pra saber como andou?\"\n- Pedido teste — \"Que tal começarmos com um pedido piloto de [X unidades]?\"\n- Objeção de timing — \"Para quando faz mais sentido revisitar isso?\"","tipo":"texto"},{"titulo":"Regras das concessões","corpo":"- Faça concessões decrescentes — a primeira é maior, as seguintes menores\n- Nunca conceda na mesma velocidade do cliente — demore antes de cada concessão\n- Valorize cada concessão: \"consegui R$280, mas é o máximo que consigo\"\n- Sempre peça algo em troca: \"se você fechar agora / levar os dois / pagar à vista\"","tipo":"texto"}]'::jsonb, 10),
('2790afa1-6dbe-4514-975b-fcb38f19d92e', NULL, '68dcf99f-99ea-43d4-9573-9697d78fdb89', 'Relacionamento e Gestão de Carteira B2B', 'texto', NULL, NULL, 0, false, '[{"titulo":"A cadência de relacionamento","corpo":"- Frequência — Tipo de contato — Objetivo\n- Toda entrega — Confirmação de recebimento + qualidade — Detectar problema antes de virar reclamação\n- Quinzenal/mensal — Check-in de giro e estoque — Identificar oportunidade de reposição\n- Trimestral — Revisão de mix e resultados — Expandir categorias, propor novo produto\n- Esporádico / sem motivo — Informação útil sem vender — Construir confiança de longo prazo","tipo":"texto"},{"titulo":"Expansão de conta — as perguntas certas","corpo":"Vender mais para quem já compra custa 5× menos e fecha 3× mais rápido do que abrir cliente novo.\n- Quais categorias o cliente ainda compra com o concorrente?\n- Qual produto você tem que ele não testou ainda?\n- Qual volume ele poderia aumentar se tivesse condição melhor?\n- Ele tem filial, loja 2, sócio que poderia indicar?","tipo":"texto"},{"titulo":"Plano de expansão — exemplo prático","corpo":"- **Descoberta:** perguntar onde compra as outras categorias e como está o fornecedor atual\n- **Piloto:** propor mix pequeno (5-10 produtos) para teste de 30 dias\n- **Argumento:** \"Você já conhece nossa entrega em higiene. Cosméticos seguem o mesmo padrão.\"\n- **Revisão:** 30 dias depois apresentar resultado e propor expansão","tipo":"texto"},{"titulo":"Como pedir indicação no B2B","corpo":"\"Fico muito feliz que o resultado foi esse. Me ajuda com uma coisa — você conhece algum outro lojista ou distribuidor que poderia se beneficiar do mesmo resultado? Não precisa ser apresentação formal, só um nome e contato já me ajuda muito.\"","tipo":"texto"},{"titulo":"O risco de contato só quando há problema","corpo":"Cliente B2B que você só liga quando há problema percebe que você existe apenas quando algo vai mal — você virou custo, não parceiro. Quando o concorrente aparecer com preço 5% menor e abordagem consultiva, o cliente vai comparar. Presença proativa cria lealdade que preço não cria.","tipo":"texto"}]'::jsonb, 10),
('8b931d87-838f-47a8-aaf8-b1a844a63cef', NULL, '215856df-fb0d-435f-abf8-b8064bcc328f', 'Simulações Completas — Atacado B2B', 'texto', NULL, NULL, 0, false, '[{"titulo":"Cenário 1 — Primeiro contato por telefone","corpo":"**Cliente:** \"Olá, vi vocês num grupo e quero saber preços.\"\n**Você:** \"Olá! Claro. Pra montar a proposta certa, me conta rapidinho — qual linha você está buscando e qual o volume médio mensal que você costuma trabalhar?\"\n**Cliente:** \"Higiene pessoal, uns 200 peças por mês.\"\n**Você:** \"Ótimo. Você compra de fornecedor único ou divide com outros? E tem algum produto específico que costuma ter problema de ruptura aí?\"\nPor que funciona: antes de qualquer preço, você qualificou volume, comportamento de compra e dor atual. Agora a proposta vai ser específica, não uma tabela genérica.","tipo":"texto"},{"titulo":"Cenário 2 — Objeção de preço no B2B","corpo":"**Cliente:** \"Tá bem acima do que pago hoje.\"\n**Você:** \"Entendo. Pode me contar mais — tá acima em valor unitário ou em custo total incluindo frete?\"\n**Cliente:** \"Unitário mesmo.\"\n**Você:** \"Me conta, o frete do fornecedor atual é cobrado à parte? Porque a gente já inclui no valor. Dependendo da sua localização, o custo total pode ficar igual ou abaixo. Posso te mostrar o comparativo?\"\nPor que funciona: antes de negociar preço, você explorou se a comparação é justa. Muitas vezes o \"mais caro\" some quando o frete é embutido.","tipo":"texto"},{"titulo":"Cenário 3 — Retenção de cliente que quer sair","corpo":"**Cliente:** \"Vou pausar os pedidos. Achei outro fornecedor mais em conta.\"\n**Você:** \"Entendo. Antes de você ir, me conta — foi só o preço ou teve alguma outra coisa que deixou a desejar no nosso serviço?\"\n**Cliente:** \"Não, o serviço foi sempre bom. É o custo mesmo.\"\n**Você:** \"Aprecio você ser honesto. Posso te fazer uma proposta de lealdade? Se você mantiver o volume médio dos últimos 3 meses, consigo rever a condição. Você me dá 15 minutos pra montar os números?\"","tipo":"texto"},{"titulo":"Cenário 4 — Follow-up após proposta sem retorno","corpo":"**Você:** \"Boa tarde, [nome]. Mandei a proposta há 5 dias e queria saber se teve chance de ver. Não quero atrapalhar — só garantir que não ficou nenhuma dúvida.\"\n**Cliente:** \"Ah sim, vi sim. Ainda estou avaliando.\"\n**Você:** \"Faz sentido. O que está pesando mais na avaliação? Posso ajudar a resolver alguma questão específica.\"","tipo":"texto"},{"titulo":"Cenário 5 — Cliente que só compra pelo menor preço","corpo":"**Cliente:** \"Mandei e-mail pra 3 fornecedores e vou fechar com quem der o menor preço.\"\n**Você:** \"Entendo! Antes de tomar essa decisão só por preço, posso te fazer uma pergunta? Se os três tiverem o mesmo produto, o que vai diferenciar quando tiver um problema de entrega ou um lote com defeito? O preço você compara em 5 minutos — mas o suporte você só descobre depois que já fechou. Me dá 10 minutos pra te mostrar como a gente funciona?\"\nPor que funciona: você não competiu no preço — você mudou o critério de decisão antes de qualquer número.","tipo":"texto"},{"titulo":"Autoavaliação — Atacado B2B","corpo":"- Quais clientes você visita/liga apenas quando há problema?\n- Quais clientes compram só 1 categoria e poderiam comprar mais?\n- Qual cliente tem perfil de indicador e você nunca pediu indicação?\n- Qual o seu BATNA na próxima negociação de desconto?","tipo":"texto"}]'::jsonb, 10),
('f35d3de7-b190-4524-ba83-800e13bfaa28', NULL, '5feeb0e7-8a00-4416-b16d-42283db74c2c', 'Mentalidade de Venda Online', 'texto', NULL, NULL, 0, false, '[{"titulo":"Cliente online vs. cliente presencial","corpo":"- Cliente presencial — Cliente online\n- Entrou na loja — já tem intenção — Está navegando — pode não ter intenção clara\n- Você controla o ambiente — Ele controla o ambiente — pode fechar aba a qualquer momento\n- Comunicação não-verbal disponível — Só texto, foto e vídeo — tudo tem que ser explícito\n- Objeção surgiu — você responde ao vivo — Objeção surgiu — ele vai embora sem falar\n- Relacionamento é fácil — rosto a rosto — Confiança tem que ser construída com provas\n- Urgência criada com presença — Urgência criada com palavras e gatilhos","tipo":"texto"},{"titulo":"Os 5 bloqueios que sabotam vendas online","corpo":"- # — Bloqueio — Consequência — Antídoto\n- 1 — Resposta lenta — Cliente esfria e compra do concorrente — Meta: responder em menos de 5 minutos em horário comercial\n- 2 — Linguagem robótica/formal — Parece atendimento automático — desengaja — Escrever como fala, com nome do cliente\n- 3 — Não mostrar o produto — Dúvida vira desistência — Vídeo, foto com contexto, review de cliente real\n- 4 — Não pedir para comprar — Cliente fica esperando convite que não vem — Sempre terminar com chamada para ação clara\n- 5 — Ignorar follow-up — 60-70% dos interessados compram depois de 1-3 follow-ups — Sequência de acompanhamento estruturada","tipo":"texto"},{"titulo":"Confiança online — os 4 pilares","corpo":"- **Prova social:** fotos de clientes reais usando o produto, avaliações com nome, antes e depois\n- **Transparência:** prazo de entrega, política de troca, como funciona o pagamento — antecipe as dúvidas\n- **Consistência:** resposta rápida sempre, mesmo que seja \"já te respondo em X minutos\"\n- **Especialidade:** você entende do produto — orientação genuína cria mais confiança do que desconto","tipo":"texto"},{"titulo":"O vendedor online de alta performance","corpo":"Não espera cliente perguntar. Antecipa dúvidas, envia conteúdo útil sem pedir nada, acompanha após a compra. No online, quem cuida do relacionamento entre compras cria o cliente que compra de novo sem pesquisar concorrente.","tipo":"texto"}]'::jsonb, 10),
('821791cc-c571-46e2-9fa9-af3d3bb6c7d2', NULL, '29c4999b-0771-4c08-ba27-700805ac4f7f', 'Funil de Vendas Digital', 'texto', NULL, NULL, 0, false, '[{"titulo":"O funil de vendas digital — 6 etapas","corpo":"- Etapa — O que acontece — Ação do vendedor\n- 1. Descoberta — Cliente vê seu produto/perfil pela primeira vez — Conteúdo atrativo, foto e vídeo de qualidade\n- 2. Interesse — Clica, salva, manda mensagem perguntando — Resposta rápida, informação clara, cria curiosidade\n- 3. Consideração — Pesquisa mais, compara com concorrente — Prova social, diferencial claro, tira dúvidas\n- 4. Intenção — Perguntou preço, pediu forma de pagamento — Proposta clara, urgência, CTA direto\n- 5. Decisão — Está prestes a comprar — pode travar aqui — Eliminar fricção no pagamento, confirmar prazo\n- 6. Pós-venda — Comprou — agora vira cliente fiel ou some — Confirmar recebimento, pedir avaliação, próxima compra","tipo":"texto"},{"titulo":"Onde a maioria das vendas se perde","corpo":"- **Etapa 2 → 3:** resposta demorou mais de 5 minutos — cliente esfriou\n- **Etapa 3 → 4:** faltou prova social para gerar confiança suficiente\n- **Etapa 4 → 5:** proposta confusa, preço sem contexto, sem chamada para ação clara\n- **Etapa 5 → decisão:** fricção no pagamento (link não funcionou, não tem o Pix, complicou)\n- **Etapa 6 → novo ciclo:** sem follow-up pós-venda = cliente não volta por si só","tipo":"texto"},{"titulo":"Como identificar o gargalo do seu funil","corpo":"Pergunte: onde estou perdendo mais clientes?\n- Sintoma — Gargalo provável\n- Muita visualização, pouca mensagem — Etapa 1-2: conteúdo não converte curiosidade em contato\n- Muita mensagem, pouca proposta solicitada — Etapa 2-3: atendimento não gera confiança suficiente\n- Muito interesse, pouco fechamento — Etapa 4-5: faltou CTA claro ou urgência\n- Fechou mas não volta — Etapa 6: sem pós-venda estruturado","tipo":"texto"},{"titulo":"A regra do follow-up","corpo":"**60-70% das vendas online fecham depois do primeiro contato.** Quem não faz follow-up abandona a maioria das vendas potenciais. Follow-up não é incomodo — é serviço.\nCadência simples:\n- Dia 1: resposta ao interesse\n- Dia 2: follow-up com informação nova (vídeo, avaliação de cliente)\n- Dia 4: urgência real ou diferencial\n- Dia 7: última mensagem — \"Ainda posso ajudar?\"","tipo":"texto"}]'::jsonb, 10),
('f657e2fa-05a4-497c-83dd-5e076142660a', NULL, '787e47e4-6a8a-4f00-83c0-b3c23d650807', 'Copywriting para Venda Online', 'texto', NULL, NULL, 0, false, '[{"titulo":"Fórmula de descrição de produto","corpo":"**Fórmula PAS+CTA:** Problema → Agitação → Solução → Chamada para Ação","tipo":"texto"},{"titulo":"Exemplo — Serum facial","corpo":"- **Problema:** \"Pele ressecada que descasca até com hidratante normal?\"\n- **Agitação:** \"Ressecamento causa envelhecimento precoce e manchas que difícil de tratar depois\"\n- **Solução:** \"Serum Hialurônico 2% — hidratação profunda em 7 dias, sem oleosidade, apto pele sensível\"\n- **CTA:** \"Manda mensagem e te explico o protocolo certo pro seu tipo de pele\"","tipo":"texto"},{"titulo":"Os 6 gatilhos mentais em texto","corpo":"- Gatilho — Como usar — Exemplo\n- Escassez — Quantidade ou tempo limitado — real — \"Últimas 8 unidades em estoque\"\n- Urgência — Prazo que muda algo — \"Pedidos até sexta chegam antes do fim de semana\"\n- Prova social — Número ou nome real de quem já comprou — \"47 clientes compraram esse mês\"\n- Autoridade — Conhecimento ou resultado que comprova — \"Recomendado por dermatologistas\"\n- Reciprocidade — Dar antes de pedir — \"Manda sua dúvida — te explico sem compromisso\"\n- Comprometimento — Pequeno sim leva ao grande sim — \"Me conta qual seu maior problema de pele\"","tipo":"texto"},{"titulo":"Chamadas para ação que convertem","corpo":"- CTA fraca — CTA forte\n- \"Se interessar, entre em contato\" — \"Manda ''QUERO'' aqui que já te separo uma unidade\"\n- \"Estamos à disposição\" — \"Manda mensagem agora — respondo em minutos\"\n- \"Saiba mais\" — \"Me conta sua rotina de pele e te indico o protocolo certo\"\n- \"Compre agora\" — \"Paga via Pix e já saiu hoje — quer que eu mande o link?\"","tipo":"texto"},{"titulo":"Copywriting para WhatsApp — regras específicas","corpo":"- Mensagens curtas — máximo 3 linhas por bolha\n- Quebrar texto em múltiplas mensagens em vez de um bloco\n- Emoji com moderação — reforça tom, não substitui argumento\n- Nome do cliente pelo menos 1x na mensagem\n- Sempre terminar com pergunta ou CTA — nunca ponto final sem convite","tipo":"texto"}]'::jsonb, 10),
('e48a9b81-a9d6-49e1-acc9-a96d81778816', NULL, '93934a91-7f71-4604-82f1-90162bb8ccf9', 'Atendimento por WhatsApp e Chat', 'texto', NULL, NULL, 0, false, '[{"titulo":"O roteiro que vende — 5 etapas","corpo":"- **Recepção calorosa:** \"Oi [nome]! Tudo bem? Em que posso ajudar hoje?\" — nunca \"olá, como posso ajudar\"\n- **Diagnóstico:** uma pergunta que revela o que o cliente realmente precisa antes de apresentar produto\n- **Apresentação personalizada:** produto específico para a necessidade identificada — não catálogo\n- **Prova:** foto, vídeo ou avaliação de cliente real — não apenas descrição\n- **CTA direto:** \"Quer que eu separe? Você paga via Pix ou cartão?\"","tipo":"texto"},{"titulo":"Mensagens modelo por etapa","corpo":"**Recepção:** \"Oi [nome]! 😊 Que bom que você entrou em contato. Me conta — você tá buscando pra sua pele ou pra presentear alguém?\"\n**Após diagnóstico (skincare):** \"Perfeito. Pra pele oleosa com tendência a acne, o que funciona muito bem aqui é o tônico com ácido salicílico 2% da COSRX. Ele equilibra o sebo sem ressecar. Deixa eu te mandar um vídeo de como usar?\"\n**Após enviar informação:** \"[Nome], o que você achou? Tem alguma dúvida sobre como usar ou sobre a entrega?\"\n**CTA de fechamento:** \"Se quiser levar, é só confirmar aqui — pago via Pix agora já separo pra você. Entrega em [X] dias. 😊\"","tipo":"texto"},{"titulo":"Follow-up sem incomodar","corpo":"- Timing — Mensagem\n- 1 dia após interesse sem compra — \"[Nome], só passando pra saber se ficou alguma dúvida sobre o [produto]. Estou aqui pra ajudar 😊\"\n- 3 dias — nova informação — \"[Nome], separei esse review de uma cliente que tinha pele parecida com a que você me descreveu. Acho que pode te ajudar a decidir. [foto/vídeo]\"\n- 7 dias — urgência real — \"[Nome], só pra te avisar que esse produto tá quase esgotando — ficaram [X] unidades. Se ainda tiver pensando, posso separar pra você com segurança?\"\n- 14 dias — último contato — \"[Nome], não quero incomodar — se não for mais o momento, tudo bem! Mas se quiser, pode voltar quando precisar. Abraço!\"","tipo":"texto"},{"titulo":"O que nunca fazer no WhatsApp de vendas","corpo":"- Não enviar catálogo completo sem contexto — 300 produtos de uma vez mata conversão\n- Não dizer \"qualquer dúvida, estou à disposição\" — fraca e passiva\n- Não deixar a conversa morrer com \"ok\" ou \"entendido\" sem próxima ação\n- Não fazer mais de 4 follow-ups — respeito ao espaço do cliente mantém a porta aberta\n- Não prometer prazo de entrega sem conferir estoque real","tipo":"texto"}]'::jsonb, 10),
('3b50b674-565d-45bd-b631-9cf21de8f386', NULL, 'bd0ed89e-2e61-4d49-b6dc-269d38dab02c', 'Objeções Online — As 6 Mais Comuns', 'texto', NULL, NULL, 0, false, '[{"titulo":"As 6 objeções mais comuns no online","corpo":"- Objeção — O que está por trás — Resposta\n- \"Tá caro\" — Não entendeu o valor ou está comparando com produto diferente — \"Me conta — caro em relação a quê? Me ajuda a entender pra ver o que posso fazer.\"\n- \"Vou pensar\" — Tem dúvida que não verbalizou — \"Claro! O que você ainda não tem certeza? Me conta que a gente resolve.\"\n- \"Não confio em compra online\" — Medo de golpe ou produto diferente da foto — \"Entendo! Você quer ver vídeo real do produto? E nossa política de troca é [X] — nada de risco pra você.\"\n- \"Vi mais barato em outro lugar\" — Ancoragem por preço — pode não ser comparação justa — \"Me conta qual produto e de onde — às vezes são produtos diferentes. Se for o mesmo, me explica e vejo o que posso fazer.\"\n- \"Não preciso agora\" — Sem urgência percebida — \"Faz sentido! Quer que eu te avise quando tiver promoção ou quando o estoque baixar?\"\n- \"Deixa pra próxima semana\" — Procrastinação — urgência não foi criada — \"Claro! Só te aviso que esse produto costuma esgotar rápido. Quer que eu reserve até amanhã pra você?\"","tipo":"texto"},{"titulo":"Anti-objeção preventiva — a estratégia mais eficiente","corpo":"Antecipar e responder objeções antes de serem levantadas elimina o bloqueio antes que ele forme.","tipo":"texto"},{"titulo":"Na descrição do produto, inclua:","corpo":"- Prazo de entrega exato (não \"rápido\")\n- Política de troca clara\n- Formas de pagamento disponíveis\n- Avaliação de cliente real com a mesma dúvida resolvida","tipo":"texto"},{"titulo":"Exemplo de mensagem com anti-objeção embutida:","corpo":"\"Esse serum custa R$89. Entrega em 2 dias úteis para CDE. Se não gostar, troca sem complicação em até 7 dias. Você paga via Pix ou cartão com ou sem parcelamento. [foto de cliente usando] — essa é a [nome], clienta nossa que tinha a mesma dúvida que você deve ter agora 😊 Quer que eu separe uma unidade pra você?\"\nEssa mensagem trata: preço, entrega, risco, pagamento, prova social — tudo antes da objeção aparecer.","tipo":"texto"},{"titulo":"O que não fazer quando o cliente diz \"tá caro\"","corpo":"- Não se justificar com \"é qualidade\" — isso não resolve a objeção\n- Não dar desconto imediato — desvaloriza o produto e sua margem\n- Não atacar o concorrente — parece inseguro\n- Perguntar antes de agir — a resposta do cliente vai guiar a sua resposta ideal","tipo":"texto"}]'::jsonb, 10),
('4361caf3-516a-415f-b58d-1cde96d723f7', NULL, 'ac84633d-3bb8-41f1-9794-30a324718677', 'Pós-venda Digital e Fidelização', 'texto', NULL, NULL, 0, false, '[{"titulo":"A cadência de pós-venda digital","corpo":"- Timing — Ação — Objetivo\n- Logo após compra — Confirmação + previsão de entrega — Reduzir ansiedade pós-compra\n- No dia da entrega — \"Chegou tudo bem? Qualquer dúvida, pode chamar\" — Detectar problema antes de virar reclamação\n- 3-7 dias após entrega — Pergunta de satisfação + pedido de avaliação — Feedback + prova social\n- 30 dias — Conteúdo de valor ou sugestão complementar — Manter presença sem pressão de venda\n- 60-90 dias — Oferta de reposição ou produto complementar — Segunda compra — LTV","tipo":"texto"},{"titulo":"Como pedir avaliação de forma natural","corpo":"**Momento certo:** 3-7 dias após o produto chegar, quando o cliente já usou e pode dar opinião real.\n**Mensagem:** \"[Nome], já faz uns dias desde que o [produto] chegou. Como você tá achando? 😊 Me ajuda muito se você puder deixar uma avaliação aqui — só uma frase já basta. Ajuda outras pessoas a saberem o que esperar e me ajuda a melhorar. Pode mandar aqui mesmo se preferir!\"\n**Por que funciona:** pedido em momento pós-experiência positiva, linguagem leve sem pressão, opção de mandar no privado (reduz barreira).","tipo":"texto"},{"titulo":"Gestão de reputação online","corpo":"- Situação — Resposta\n- Avaliação positiva — Agradecer pelo nome, mencionar algo específico que eles disseram\n- Avaliação negativa pública — Responder em público com empatia + resolução + contato privado: \"Sentimos muito! Já entrei em contato para resolver\"\n- Avaliação negativa privada — Resolver primeiro, pedir avaliação atualizada depois de resolvido\n- Sem resposta do cliente após entrega — Follow-up gentil: \"Chegou tudo certinho?\"","tipo":"texto"},{"titulo":"Reativação de clientes inativos","corpo":"Cliente que comprou há mais de 60 dias sem nova compra = candidato a reativação.\n**Mensagem de reativação:** \"Oi [nome]! Faz um tempo que não falamos. Você comprou [produto] conosco em [mês] — como está sendo a experiência? 😊 Temos um produto novo que achei que você ia gostar — [produto relacionado]. Quer dar uma olhada?\"\n**Por que funciona:** menciona a compra anterior (mostra que você lembra), pergunta pela experiência (interesse genuíno), sugere algo relacionado (relevante, não aleatório).","tipo":"texto"},{"titulo":"O valor do cliente fidelizado","corpo":"- Compra com mais frequência — custo de aquisição zero\n- Gasta mais por compra — confia mais\n- Indica amigos — aquisição de custo baixíssimo\n- Menor sensibilidade a preço — 5-10% a mais sem objeção\n- Mais tolerante a problemas — relacionamento cria goodwill\n**LTV (Lifetime Value):** cliente fidelizado vale 3-7x o cliente de única compra. Cada real investido em pós-venda tem retorno muito maior do que o mesmo real em aquisição.","tipo":"texto"}]'::jsonb, 10),
('f8b090ab-b9ff-43c2-8a38-42b9653c4b26', NULL, '772d2900-6774-422f-abdf-bdb2b5a5e3fe', 'História e Filosofia do K-Beauty', 'texto', NULL, NULL, 0, false, '[{"titulo":"1.1 — Origens: Mais de 5.000 Anos de Cultura de Pele","corpo":"O skincare coreano não nasceu na prateleira de uma farmácia. Nasceu na filosofia, na medicina tradicional e na cultura de um povo que sempre tratou a pele como reflexo da saúde interna.","tipo":"texto"},{"titulo":"Era Três Reinos (57 a.C. – 668 d.C.)","corpo":"Os três reinos — Goguryeo, Baekje e Silla — já documentavam uso de ingredientes naturais na pele. Mulheres aristocratas utilizavam:\n- **Camellia oil** — hidratação e proteção\n- **Arroz fermentado** — tônico clareador (trabalhadoras de cervejarias de arroz tinham rostos notavelmente mais jovens que o restante do corpo)\n- **Chá verde** — antioxidante tópico\n- **Ginseng** — circulação e vitalidade","tipo":"texto"},{"titulo":"Era Joseon (1392–1897) — O Padrão Estético se Consolida","corpo":"A era Joseon estabeleceu o ideal estético que ainda ressoa no K-beauty contemporâneo: **pele como porcelana** (도자기 피부 / dojaagi pibu).\n- Pele uniforme, sem manchas\n- Textura lisa e translúcida\n- Hidratação visível\n- Ausência de vermelhidão\nA medicina **Hanbang (한방)** — medicina herbal tradicional — classificava ingredientes por propriedades de \"esfriamento\" ou \"aquecimento\" da pele, criando o conceito de skincare como medicina preventiva, não corretiva.","tipo":"texto"},{"titulo":"Modernização (1945–1990)","corpo":"- **1945:** Fundação da Pacific Corporation (hoje Amorepacific) — maior empresa de cosméticos da Ásia\n- **1954:** Primeiro creme de massa coreano — ABC Powder Cream\n- **Anos 1990:** Marcas como Innisfree, Etude House e Missha democratizam o skincare","tipo":"texto"},{"titulo":"1.2 — A Filosofia Central do K-Beauty","corpo":"","tipo":"texto"},{"titulo":"Ocidental vs. Coreano — A Grande Divergência","corpo":"- Dimensão — Skincare Ocidental — Skincare Coreano\n- Filosofia — Corretivo — trata quando aparece — Preventivo — mantém antes de aparecer\n- Foco — Eficácia pontual, resultados rápidos — Saúde da barreira a longo prazo\n- Passos — 3–5 — 7–12\n- Ativos — Alta concentração — Concentrações menores, acumulação gradual\n- Tolerância à irritação — \"Se ardeu, funcionou\" — Irritação = alarme, não eficácia\n- Pele ideal — Maquiável, coberta — Nua, saudável, luminosa por si só\n- SPF — Recomendado — Mandatório","tipo":"texto"},{"titulo":"\"Healthy Skin First\"","corpo":"**Pele saudável não precisa de maquiagem. Pele saudável é o destino, não o ponto de partida.**\nImplicação comercial direta: quando cliente chega pedindo produto pontual para mancha, o consultor treinado vende rotina completa — porque a mancha é sintoma de barreira comprometida, não problema isolado.","tipo":"texto"},{"titulo":"Filosofia da Camada (레이어링 / Layering)","corpo":"O skincare coreano funciona como uma construção em camadas:\n- Limpeza (barreira limpa)\n- Tônico (prepara e primeira hidratação)\n- Essence (tratamento base)\n- Ampoule/Sérum (ativo concentrado)\n- Emulsão/Creme (selagem)\n- SPF (proteção) ou Sleeping Mask (noturno)\nCada camada é **complementar, não redundante**. Isso é o que separa vendedor de consultor.","tipo":"texto"},{"titulo":"1.3 — Como a Coreia se Tornou Líder Mundial","corpo":"","tipo":"texto"},{"titulo":"O Papel do Governo: Hallyu (한류)","corpo":"Em 1999, o governo coreano lançou o **Korean Wave (Hallyu)** — estratégia nacional de exportação cultural após a crise financeira de 1997. Três pilares: dramas, K-pop e cosméticos.\nResultado: atriz coreana com pele perfeita em drama → mundo quer saber o que ela usa → indústria cosmética pronta para responder.","tipo":"texto"},{"titulo":"Regulamentação Inteligente","corpo":"A Coreia tem categoria de \"cosmecêuticos\" — concentrações maiores que cosmético comum sem exigir registro farmacêutico. Inovação chega ao mercado 3–5x mais rápido que na Europa ou EUA.","tipo":"texto"},{"titulo":"Consumidor Interno como Motor de Inovação","corpo":"- Média de 7–8 produtos na rotina diária\n- App **Hwahae (화해)** — 11+ milhões de usuários avaliando INCI lists de produtos\n- Literacia alta em ingredientes: sabem o que é niacinamida, ceramida, peptídeo\n- Feedback rápido força inovação em ciclos de 12–18 meses","tipo":"texto"},{"titulo":"Inovações Tecnológicas Coreanas","corpo":"- Formato — Inovação — Impacto\n- Cushion Compact — Amorepacific patenteou em 2008 — Copiado por Lancôme, Dior, L''Oréal\n- Sheet Mask — Inspirada em curativos clínicos pós-procedimento — Bilhões de unidades exportadas/ano\n- Ampoule — Sérum hiper-concentrado em ciclos — Adaptação de tratamentos clínicos para uso doméstico\n- Sleeping Mask — Máscara deixada durante o sono — Tratamento intensivo sem experiência de produto\n- Essence — Camada líquida de tratamento base — Inexistente no skincare ocidental clássico","tipo":"texto"},{"titulo":"Fermentação — A Biotecnologia Tradicional Modernizada","corpo":"O processo de fermentação:\n- Reduz tamanho molecular → maior penetração cutânea\n- Cria novos bioativos não presentes no ingrediente original\n- Aumenta biodisponibilidade de vitaminas e aminoácidos\n- Melhora tolerância cutânea","tipo":"texto"},{"titulo":"1.4 — O Consumidor da Pontocom: Perfis e Abordagens","corpo":"- Perfil — Comportamento — Abordagem\n- Iniciante curioso — Viu TikTok/Reels, não sabe por onde começar — Simplifique em 3 passos. Não sobrecarregue\n- Entusiasta intermediário — Já tem rotina, quer otimizar — Vá fundo em ingredientes\n- Compradora por preço — Quer resultado, olha o ticket — Âncora com produto caro, ofereça alternativa inteligente\n- Turista/revendedora — Compra para revender no Brasil/Argentina — Volume, marcas conhecidas, trending\n- Pele de cor média/escura — Preocupa com manchas, hiperpigmentação — Tranexâmico, niacinamida, arbutin","tipo":"texto"},{"titulo":"Estudo de Caso","corpo":"**Cenário:** Cliente entra pedindo \"um creme hidratante coreano que viu no TikTok\".\n**Abordagem correta:** Valide a percepção → explique layering em 30 segundos → faça 2 perguntas de diagnóstico (\"sua pele fica oleosa ou seca ao longo do dia? usa protetor solar?\") → construa mini-rotina de 3 passos. O creme vira item 3 de 3. Ticket médio: 3–4x maior.","tipo":"texto"}]'::jsonb, 10),
('e08f77bf-4170-44d5-99cb-d1f0b397a91f', NULL, '20f979d7-4ffb-44f2-bf4f-9d64bbc6925a', 'Anatomia da Pele', 'texto', NULL, NULL, 0, false, '[{"titulo":"2.1 — Estrutura: O Que é a Pele","corpo":"A pele é o maior órgão do corpo humano: ~1,5–2 m², 3,5–10 kg. Três funções primárias:\n- **Proteção** — barreira física contra patógenos, UV, poluição, agentes químicos\n- **Regulação** — temperatura corporal, retenção hídrica, pH\n- **Sensação** — receptores de toque, pressão, temperatura, dor\nAs três camadas: **Epiderme** (superfície, onde produtos atuam) → **Derme** (colágeno, elastina, ácido hialurônico) → **Hipoderme** (gordura, vasos profundos).","tipo":"texto"},{"titulo":"2.2 — Epiderme e o Stratum Corneum","corpo":"A epiderme tem 5 sub-camadas. A mais importante para o skincare é o **Stratum Corneum** (camada mais superficial) — estrutura de \"tijolos e argamassa\":\n- **Tijolos** = corneócitos (células mortas queratinizadas)\n- **Argamassa** = ceramidas (50%) + ácidos graxos (10–20%) + colesterol (25%)","tipo":"texto"},{"titulo":"Barreira Íntegra vs. Comprometida","corpo":"- Barreira Saudável — Barreira Comprometida\n- Hidratação retida — TEWL (perda de água) aumentado → pele seca\n- Patógenos bloqueados — Sensibilidade e vermelhidão\n- Irritantes impedidos — Acne piora\n- Pele resistente — Manchas aparecem mais fácil\n**Regra de ouro:** antes de recomendar qualquer ativo potente (vitamina C, retinol, ácidos), pergunte se a barreira está saudável. Barreira comprometida + ativo potente = irritação + cliente insatisfeito.","tipo":"texto"},{"titulo":"NMF — Natural Moisturizing Factor","corpo":"Cocktail de substâncias hidrófilas dentro dos corneócitos que mantêm o stratum corneum hidratado:\n- Aminoácidos livres (40%)\n- PCA (ácido pirrolidona carboxílico) (12%)\n- Ácido láctico e sais (12%)\n- Uréia (7%)\nIngredientes como glicerina, ácido hialurônico, uréia e aminoácidos funcionam porque imitam ou reforçam o NMF — transforma um produto \"simples\" em solução científica.","tipo":"texto"},{"titulo":"Como as Manchas se Formam — Melanócitos","corpo":"Na base da epiderme ficam os melanócitos — células que produzem melanina:\n- Gatilho (UV / inflamação / hormônio) ativa o melanócito\n- Melanina produzida em excesso é transferida para queratinócitos vizinhos\n- Queratinócitos \"tingidos\" sobem para a superfície\n- Mancha visível\n**Por que leva 4–8 semanas para tratar manchas:** esse ciclo de turnover celular dura exatamente esse tempo. Produtos que \"clarareiam em 3 dias\" não existem.","tipo":"texto"},{"titulo":"2.3 — Derme: O Colchão Estrutural","corpo":"Abaixo da epiderme (1–4 mm). Contém as estruturas que determinam firmeza e elasticidade:\n- **Colágeno (70–80%):** resistência e estrutura. Produzido por fibroblastos. Degradado por UV, poluição, inflamação.\n- **Elastina (2–4%):** permite que a pele volte à forma. Produção quase cessa após os 20 anos.\n- **Ácido Hialurônico:** retém até 1.000x seu peso em água. Reduz com a idade.\n- **Fibroblastos:** ativados por vitamina C, retinol, peptídeos — produzem colágeno, elastina e HA.","tipo":"texto"},{"titulo":"2.4 — Barreira Cutânea: O Conceito Central do K-Beauty","corpo":"","tipo":"texto"},{"titulo":"Manto Ácido","corpo":"Filme hidrolipídico na superfície da pele:\n- **pH entre 4,5–5,5** (levemente ácido)\n- Inibe bactérias patogênicas, mantém enzimas da barreira ativas\nO que compromete o pH:\n- Sabonetes alcalinos (pH 9–10) — destroem o manto ácido\n- Álcool desnaturante em tônicos\n- Esfoliação excessiva\n**Argumento de venda:** sabonetes comuns de banheiro têm pH 9–10. Um bom cleanser coreano tem pH 5–6. Isso sozinho justifica a troca de produto.","tipo":"texto"},{"titulo":"Microbioma Cutâneo","corpo":"A pele hospeda ~10¹² microrganismos em equilíbrio. O que desequilibra:\n- Uso excessivo de antibióticos tópicos\n- Álcool em produtos\n- Esfoliação agressiva\n- Sabonetes antibacterianos diários\nIngredientes que suportam: prebióticos (inulina), probióticos (lactobacillus ferment), postbióticos (filtrados de fermentação).","tipo":"texto"},{"titulo":"2.5 — Como a Pele Envelhece","corpo":"- Faixa etária — O que acontece\n- 20s — Turnover desacelera: 21 dias → 28 dias\n- 30s — Colágeno cai ~1%/ano. Primeiras linhas fixas\n- 40s — HA natural reduz 50%. Poros mais visíveis\n- 50s+ — Menopausa → pele mais fina, mais seca, menos firme\n**80% dos sinais de envelhecimento visíveis são causados por UV.** Esta é a estatística mais poderosa para vender protetor solar. Nenhum sérum de colágeno compensa a ausência de fotoproteção.","tipo":"texto"},{"titulo":"2.6 — Hidratação vs. Oleosidade","corpo":"**Erro mais comum:** confundir pele oleosa com pele hidratada.\n- Conceito — O que é — Ingredientes\n- Hidratação — Conteúdo de água nas células — Ácido hialurônico, glicerina, uréia, pantenol\n- Oleosidade — Quantidade de sebo produzido pelas glândulas sebáceas — Regulado por hormônios, pH, genética\n- Emolientes — Preenchem lacunas entre corneócitos — Ceramidas, esqualano, óleos vegetais\n- Oclusivos — Criam filme físico que reduz TEWL — Vaselina, manteiga de karité, dimeticone\n**Insight contraintuitivo:** pele oleosa pode ser desidratada. Quando a pele está desidratada, produz mais sebo como mecanismo compensatório. Solução não é reduzir oleosidade — é hidratar.","tipo":"texto"},{"titulo":"2.7 — Estimuladores de Colágeno","corpo":"Em ordem de eficácia comprovada:\n- **Retinol/Retinoides** — estimulam fibroblastos diretamente, inibem MMPs\n- **Vitamina C** — cofator essencial na síntese de colágeno\n- **Peptídeos de sinalização** — \"mensageiros\" que instruem fibroblastos\n- **EGF (Epidermal Growth Factor)** — estimula renovação celular\n- **PDRN (Polinucleotídeos)** — fragmentos de DNA que ativam receptores de crescimento\n- **Niacinamida** — estimula produção indireta de ceramidas e melhora o microambiente","tipo":"texto"}]'::jsonb, 10),
('44249e69-1b46-4d22-ac5a-295de909f0d7', NULL, '7251ecef-fd5a-425d-bc74-ec846f716040', 'Tipos de Pele', 'texto', NULL, NULL, 0, false, '[{"titulo":"3.1 — Os Tipos de Pele","corpo":"O sistema de classificação mais utilizado clinicamente inclui 7 tipos. Conhecer cada um é essencial para nunca errar uma indicação.","tipo":"texto"},{"titulo":"Pele Normal","corpo":"Equilíbrio entre oleosidade e hidratação. Poros pequenos, textura uniforme, raras imperfeições. **Erro comum:** cliente com pele normal acha que \"não precisa de rotina\" — pele normal sem cuidado vira mista ou sensível com o tempo.\nNecessidades: manutenção do equilíbrio, hidratação leve, SPF, antioxidantes preventivos.","tipo":"texto"},{"titulo":"Pele Seca","corpo":"Sensação de aperto após limpeza, textura áspera ou descamativa, poros pouco visíveis, TEWL elevado, produção de sebo baixa.\n**Causas:** genética, idade, clima seco/frio, banhos quentes, clensers agressivos, histórico de dermatite atópica.\n**Ingredientes prioritários:** ceramidas, esqualano, shea butter, ácido hialurônico, glicerina, pantenol, uréia.\nEvitar: álcool, fragrance, mentol.","tipo":"texto"},{"titulo":"Pele Oleosa","corpo":"Brilho ao longo do dia, poros dilatados na zona T, propensa a comedões e acne. **Causa irônica:** rotina muito agressiva que resseca → pele compensa com mais sebo.\n**Ingredientes prioritários:** niacinamida, ácido salicílico, ácido azelaico, zinco. SPF leve, não comedogênico.\nEvitar: hidratantes pesados, óleos comedogênicos (coco, trigo).","tipo":"texto"},{"titulo":"Pele Mista","corpo":"Zona T (testa, nariz, queixo) oleosa; bochechas normais ou secas. Causa: maior densidade de glândulas sebáceas na zona T.\n**Abordagem:** tratamento por zona (multimasking). Produtos balanceados que não super-hidratem a zona T nem resssequem as bochechas.\n**Ingredientes:** niacinamida (equilibra), ácido hialurônico de baixo peso molecular (hidrata sem engordar).","tipo":"texto"},{"titulo":"Pele Sensível","corpo":"**IMPORTANTE:** sensível não é tipo de pele — é uma condição que pode afetar qualquer tipo. Causas: genética, rosácea, dermatite atópica, rotina agressiva, overload de ativos.\n**Ingredientes prioritários:** ceramidas, centella asiatica, madecassoside, aloe vera, pantenol, heartleaf, beta-glucan. Zero fragrance, zero álcool desnaturante, zero mentol.\nIntrodução de qualquer novo produto: um por vez, intervalo de 2 semanas. Patch test obrigatório.","tipo":"texto"},{"titulo":"Pele Acneica","corpo":"**IMPORTANTE:** Acne é doença. Casos moderados a graves exigem dermatologista — skincare complementa, não substitui tratamento médico.\n- Tipo de lesão — Características — Abordagem\n- Comedão aberto (cravo preto) — Poro dilatado, oxidado — BHA (salicílico), esfoliação\n- Comedão fechado (cravo branco) — Poro fechado — BHA, retinol\n- Pápula — Vermelho, inflamado, sem pus — Anti-inflamatórios, BHA\n- Pústula — Com pus visível — BHA, tea tree, benzoil peróxida\n- Nódulo/Cisto — Profundo, doloroso — Dermatologista obrigatório","tipo":"texto"},{"titulo":"Pele Madura","corpo":"Linhas e rugas, perda de firmeza, manchas solares, poros mais visíveis (elastina reduzida). Necessidades: estimuladores de colágeno (retinol, vitamina C, peptídeos), hidratação intensa, SPF rigoroso, antioxidantes.","tipo":"texto"},{"titulo":"3.2 — Protocolo dos 30 Minutos","corpo":"Instrução para o cliente identificar o próprio tipo:\n- Lavar o rosto com cleanser suave\n- Não aplicar nenhum produto\n- Aguardar 30 minutos e observar\n- Resultado após 30 min — Tipo provável\n- Brilho por todo o rosto — Oleosa\n- Aperto, descamação, opacidade — Seca\n- Brilho só na zona T — Mista\n- Confortável, sem brilho excessivo — Normal\n- Vermelhidão, ardência, coceira — Sensível","tipo":"texto"},{"titulo":"3.3 — Diagnóstico no Atendimento: 5 Perguntas","corpo":"**Nunca pergunte diretamente \"qual seu tipo de pele?\" — a maioria não sabe ou está errada.**\n- **P1:** \"Ao longo do dia, sua pele fica com brilho? Em que região?\" → localiza oleosidade\n- **P2:** \"Após lavar o rosto, sente aperto ou desconforto?\" → identifica ressecamento\n- **P3:** \"Você tem espinhas ou cravos com frequência?\" → grau de acne\n- **P4:** \"Sua pele fica vermelha ou irritada com facilidade? Reage a produtos novos?\" → sensibilidade\n- **P5 (mais importante):** \"Qual sua principal preocupação com a pele agora?\" → conecta necessidade real ao produto certo\nRespostas para P5:\n- Manchas → depigmentantes\n- Brilho excessivo → reguladores de sebo\n- Rugas → estimuladores de colágeno\n- Acne → BHA + anti-inflamatório\n- Ressecamento → barreira + humectantes","tipo":"texto"},{"titulo":"3.4 — Contexto Latino-Americano: Fototipos","corpo":"Fototipo predominante em Ciudad del Este: Fitzpatrick III, IV e V (pele morena a escura).\n- Característica — Relevância\n- Maior resistência ao câncer de pele — Não significa que não precisa de SPF — manchas e fotoenvelhecimento ocorrem normalmente\n- Maior tendência à hiperpigmentação pós-inflamatória — Qualquer inflamação (acne, corte) deixa mancha mais escura e por mais tempo\n- Melasma mais prevalente — Hormônios + UV em fototipo alto = melasma recorrente\n**Ingredientes prioritários para fototipos III–V:** niacinamida, ácido tranexâmico, arbutin, ácido azelaico, vitamina C, SPF de amplo espectro (UVA + UVB).","tipo":"texto"}]'::jsonb, 10),
('fd8bbd4f-f391-4857-861d-2c45632a8ff2', NULL, '73394e8e-6624-455a-8517-2415f398affa', 'Diagnóstico de Clientes — 20 Cenários', 'texto', NULL, NULL, 0, false, '[{"titulo":"Framework de Diagnóstico","corpo":"Memorize o fluxo e nunca pule etapas:\n**OUVIR → PERGUNTAR → IDENTIFICAR → EDUCAR → RECOMENDAR → VENDER**\nClientes que se sentem ouvidos compram mais e reclamam menos.","tipo":"texto"},{"titulo":"Cenários de Acne e Oleosidade","corpo":"","tipo":"texto"},{"titulo":"Cenário 1 — Adolescente com acne, nunca usou nada","corpo":"**Cliente:** \"Tenho 17 anos, pele muito oleosa, muita espinha, nunca usei nada.\"\n**Análise:** acne hormonal adolescente, barreira virgem. Prioridade: gentileza + eficácia.\n**Rotina:** cleanser suave pH-balanceado → tônico BHA 0,5–1% (3x/semana) → sérum niacinamida 10% → hidratante gel oil-free → SPF não comedogênico.\n**Script:** \"A pele adolescente produz muito sebo por causa dos hormônios — é normal, não é falta de higiene. O que vamos fazer é equilibrar com produtos leves e um ácido que vai limpar dentro do poro devagar.\"","tipo":"texto"},{"titulo":"Cenário 2 — Cravos no nariz, quer diminuir poros","corpo":"**Cliente:** \"Tenho 25 anos, pele oleosa, muitos cravos no nariz. Quero diminuir os poros.\"\n**Dizer ao cliente:** \"Poro não encolhe — ele é genético. Mas com BHA dentro do poro + niacinamida regulando o sebo, eles ficam muito menos visíveis. Resultado real em 6–8 semanas.\"\n**Rotina:** double cleanse (oil + foam) → tônico BHA 2% → sérum niacinamida + zinco → gel hidratante.","tipo":"texto"},{"titulo":"Cenário 3 — Manchas de acne (PIH)","corpo":"**Cliente:** \"Tenho 30 anos, pele oleosa, acne ocasional, mas principalmente manchas das espinhas que ficam.\"\n**Análise:** PIH (hiperpigmentação pós-inflamatória). Problema principal já não é a acne — é a mancha.\n**Rotina:** cleanser low pH → BHA (3x/semana, manutenção) → vitamina C (manhã) + niacinamida (noite) → SPF rigoroso.\n**Script:** \"O protetor solar é obrigatório — sem ele, a mancha escurece novamente e qualquer produto fica sem efeito.\"","tipo":"texto"},{"titulo":"Cenário 4 — Pele que descasca com maquiagem","corpo":"**Cliente:** \"Pele oleosa, uso bastante maquiagem, no final do dia descasca no T e brilha no resto.\"\n**Análise:** pele mista desidratada com barreira comprometida pelo cleanser errado ou remoção inadequada.\n**Script:** \"Essa descamação embaixo da maquiagem é sinal de pele desidratada — a maquiagem está grudando nas células mortas. Vamos hidratar direito e sua maquiagem vai durar muito mais.\"","tipo":"texto"},{"titulo":"Cenários de Manchas e Hiperpigmentação","corpo":"","tipo":"texto"},{"titulo":"Cenário 5 — Melasma (fototipo médio/alto)","corpo":"**Cliente:** \"Tenho 35 anos, pele morena, manchas escuras na testa e bochechas. Piora no verão.\"\n**Análise:** melasma (distribuição clássica, piora com sol). Condição crônica — controle, não cura.\n**Rotina:** cleanser suave → tônico com tranexâmico ou niacinamida → vitamina C (manhã) + ácido azelaico ou tranexâmico (noite) → SPF 50+ PA++++ obrigatório, reaplicar a cada 2h.\n**Expectativa:** \"Melasma não tem cura — ele é controlado. Com essa rotina e protetor rigoroso, ele clareia e para de progredir. Mas se parar o protetor, volta. É compromisso de longo prazo.\"\n**IMPORTANTE:** melasma moderado a severo precisa de dermatologista. Encaminhe para avaliação médica.","tipo":"texto"},{"titulo":"Cenário 6 — Pós-parto, manchas da gravidez","corpo":"**Cliente:** \"Tive bebê há 6 meses, manchas apareceram durante a gravidez.\"\n**Ingredientes seguros para lactantes:** niacinamida ✓, ácido azelaico ✓, vitamina C ✓, tranexâmico ✓ (tópico), bakuchiol ✓, SPF mineral ✓.\n**Evitar:** retinol ✗, hidroquinona ✗, AHA em alta concentração (cautela).","tipo":"texto"},{"titulo":"Cenário 7 — Pele negra com PIH","corpo":"**Cliente:** \"Tenho 22 anos, pele negra, manchas escuras onde tive espinhas. As marcas ficam meses.\"\n**Honestidade necessária:** \"Em pele mais escura, as manchas demoram mais para clarear — isso é fisiológico, não falha do produto. O resultado vem com consistência de 3–6 meses.\"\n**Prioridade 1:** acabar com a acne (sem inflamação, sem nova PIH). Stack: niacinamida 10% (noite) + vitamina C estável (manhã) + tranexâmico como spot treatment + SPF todos os dias.","tipo":"texto"},{"titulo":"Cenários de Ressecamento e Sensibilidade","corpo":"","tipo":"texto"},{"titulo":"Cenário 8 — Barreira comprometida severa","corpo":"**Cliente:** \"Minha pele descasca o tempo todo, fica vermelha, qualquer produto irrita.\"\n**Análise:** barreira comprometida severa. Pode ser dermatite atópica. Abordagem: simplificar ao máximo.\n**Protocolo de recovery:** APENAS cleanser suavíssimo (leite ou balm) + hidratante com ceramidas (zero ativos) + SPF mineral. Eliminar TUDO por 4 semanas.\n**Script:** \"Quando a pele está assim, ela precisa de descanso, não de mais produtos. Vamos simplificar, reconstruir a barreira, e só depois de 4 semanas introduzir qualquer ativo.\"","tipo":"texto"},{"titulo":"Cenário 9 — Rosácea diagnosticada","corpo":"**Cliente:** \"Tenho rosácea diagnosticada pelo dermatologista.\"\n**Ingredientes indicados:** azelaico (único com evidência clínica para rosácea), centella asiatica, ceramidas, niacinamida (com cautela), aloe vera.\n**Proibidos:** álcool desnaturante, mentol, eucalipto, fragrance, AHA em alta concentração, calor.","tipo":"texto"},{"titulo":"Cenário 10 — Irritação com retinol","corpo":"**Cliente:** \"Uso retinol há 2 semanas e minha pele descascou demais e ficou vermelha.\"\n**Diagnóstico:** irritação (não purging) — concentração muito alta ou frequência demais.\n**Protocolo rescue:** pause o retinol por 2 semanas → ceramidas + hidratante suave apenas → reintroduzir retinol 0,025% 1x/semana com buffer (hidratante antes = \"sandwich method\").","tipo":"texto"},{"titulo":"Cenários Anti-Aging","corpo":"","tipo":"texto"},{"titulo":"Cenário 11 — Pele madura, foco preventivo","corpo":"**Cliente:** \"Tenho 40 anos, pele normal, quero prevenir o envelhecimento.\"\n**Rotina ideal:** essence fermentada → vitamina C 15–20% (manhã) → retinol 0,1% (noite, 3–4x/semana) → peptídeos → SPF 50+ PA++++ diário.\n**Script:** \"Você está na fase ideal para começar — prevenir é sempre mais fácil que corrigir. A vitamina C de manhã + retinol de noite é a dupla mais estudada em anti-aging.\"","tipo":"texto"},{"titulo":"Cenário 12 — Presente para a namorada","corpo":"**Cliente:** \"Quero presente para minha namorada que gosta de skincare. Budget de US$50.\"\n**Abordagem:** não tente descobrir tipo de pele da pessoa ausente. Venda segurança com ingredientes universais.\n**Kit sugerido:** sérum de snail mucin (universal, seguro) + sheet mask pack (experiência imediata) + sleeping mask + lip balm. Embrulhado = presente instagramável.","tipo":"texto"},{"titulo":"Cenários Especiais","corpo":"","tipo":"texto"},{"titulo":"Cenário 13 — Homem nunca usou nada","corpo":"**Abordagem:** sem jargão K-beauty. Foco em simplicidade e resultado.\n**Rotina de 3 passos:** facial wash (não sabonete de corpo) + hidratante com niacinamida + SPF gel leve.\n**Script:** \"Três produtos, dois minutos por dia. Resultados em 3 semanas.\"","tipo":"texto"},{"titulo":"Cenário 14 — Revendedora","corpo":"**Cliente:** \"Sou revendedora, quero produtos que vendam bem no Brasil.\"\n**Top produtos para revenda:** Cosrx Snail 96 Essence, Beauty of Joseon Relief Sun, Some By Mi AHA BHA PHA Toner, Laneige Lip Sleeping Mask.\n**Script:** \"Esses são os produtos com maior reconhecimento nas redes — quem pesquisa skincare no TikTok já ouviu falar deles. Vendem fácil porque a demanda já existe.\"","tipo":"texto"},{"titulo":"Cenário 15 — Maquiagem que piora a pele","corpo":"**Cliente:** \"Uso base todo dia, minha pele está piorando, cravos aumentaram.\"\n**Problema central:** remoção inadequada de maquiagem.\n**Script:** \"O principal aqui é a remoção. Maquiagem que fica na pele entope o poro — água e sabonete não dissolvem pigmento e protetor. O óleo de limpeza vai mudar tudo.\"","tipo":"texto"},{"titulo":"30 Perguntas Diagnósticas Prontas","corpo":"- Qual seu maior incômodo com a pele agora?\n- Sua pele fica oleosa ao longo do dia?\n- Sente ressecamento ou aperto após lavar?\n- Tem espinhas com frequência? Onde?\n- Tem manchas? São antigas ou novas?\n- Sua pele fica vermelha facilmente?\n- Já usou algum produto que irritou?\n- Usa protetor solar? Qual?\n- Usa maquiagem? Com que frequência?\n- Como você limpa o rosto atualmente?\n- Sua pele muda com o ciclo menstrual?\n- Está grávida ou amamentando?\n- Usa algum medicamento contínuo (isotretinoína, hormônios)?\n- Qual o clima onde você mora/trabalha?\n- Tem orçamento em mente?\n- Prefere rotina simples ou não se importa com mais passos?","tipo":"texto"}]'::jsonb, 10),
('5fee72e2-af67-4031-b90b-c0eb55c75c1f', NULL, '0179ff35-cb67-4a38-ba5c-93e89b99eb96', 'Ingredientes de Hidratação e Barreira', 'texto', NULL, NULL, 0, false, '[{"titulo":"Como Ler uma Lista INCI","corpo":"INCI = International Nomenclature of Cosmetic Ingredients — a lista de ingredientes no rótulo.\n- Listados em **ordem decrescente de concentração**\n- Ingredientes acima de 1%: na ordem de quantidade\n- Abaixo de 1%: fabricante pode listar em qualquer ordem\n- Se ingrediente ativo aparece no final → concentração provavelmente baixa demais para efeito real","tipo":"texto"},{"titulo":"NIACINAMIDA — O Ingrediente Universal","corpo":"**O que é:** Forma de vitamina B3 (ácido nicotínico amida). Hidrossolúvel.\n**O que faz:**\n- Inibe transferência de melanina → clareia manchas\n- Regula produção sebácea → reduz brilho em pele oleosa\n- Fortalece barreira cutânea → estimula ceramidas e ácidos graxos\n- Anti-inflamatório → reduz vermelhidão, melhora acne\n- Antioxidante → protege contra dano oxidativo\n- Minimiza poros (melhora elasticidade ao redor)\n**Para quem serve:** praticamente todos os tipos de pele. O ingrediente mais versátil do K-beauty.\n**Combinações que potencializam:** com zinco (controle de sebo), com HA (hidratação + uniformização), com ceramidas (barreira), com azelaico (manchas).\n**Concentração eficaz:** 2–10%. Abaixo de 2% = pouco efeito. Acima de 10% = possível irritação em pele sensível.\n**Horário:** manhã e/ou noite. **Tempo para resultados:** 4–8 semanas para manchas; 2–4 semanas para controle de sebo.","tipo":"texto"},{"titulo":"ÁCIDO HIALURÔNICO (AH) — Hidratação Multidepth","corpo":"**O que é:** Glicosaminoglicano produzido naturalmente no corpo. Retém até 1.000x seu peso em água.\n**Pesos moleculares — isso é crucial:**\n- Peso Molecular — Penetração — Efeito\n- Alto (>1000 kDa) — Superfície — Filme hidratante, efeito imediato de maciez\n- Médio (500 kDa) — Epiderme superior — Hidratação mais profunda\n- Baixo (<50 kDa) — Epiderme profunda — Hidratação de longa duração, suporta barreira\n- Micro/Nano (<5 kDa) — Possível acesso à derme — Efeito mais profundo e duradouro\n**Produtos com múltiplos pesos moleculares são superiores** — hidratam em múltiplas profundidades.\n**CUIDADO IMPORTANTE:** AH é humectante — puxa água do ambiente para a pele. Em ambientes secos (ar condicionado), sem oclusivo por cima, pode desidratar a pele puxando água de dentro para fora. **Sempre aplicar seguido de emoliente ou creme.**","tipo":"texto"},{"titulo":"CERAMIDAS — Reconstrutoras de Barreira","corpo":"**O que são:** Lipídios que compõem ~50% da \"argamassa\" do stratum corneum.\n**O que fazem:** reconstroem e mantêm a barreira, reduzem TEWL, protegem contra irritantes externos, suportam o microbioma.\n**Para quem serve:** pele seca, sensível, dermatite atópica, pele pós-retinol ou pós-ácidos. **Sem contraindicação.**\n**Quando usar:** DEPOIS dos ativos — como \"rescue\" da barreira. Fórmula ideal: ceramidas + colesterol + ácidos graxos na proporção 1:1:1.\n**Tempo para resultados:** melhora da barreira visível em 2–4 semanas.","tipo":"texto"},{"titulo":"CENTELLA ASIATICA — Anti-inflamatório Potente","corpo":"**O que é:** Planta medicinal asiática (Gotu Kola). Compostos ativos: madecassoside, asiaticoside, asiatic acid, madecassic acid.\n**O que faz:**\n- Anti-inflamatório potente — reduz vermelhidão, calmante\n- Estimula produção de colágeno (ativa fibroblastos)\n- Cicatrizante (aceleração de wound healing)\n- Fortalece barreira cutânea\n- Antioxidante e antimicrobiano leve\n**Para quem serve:** pele sensível ou irritada, acneica, madura, pós-procedimento, rosácea. Universalmente compatível.\n**Marcas coreanas famosas com centella:** Purito, Some By Mi (CICA), Dr. Jart+ (Cicapair), Benton, Beauty of Joseon.","tipo":"texto"},{"titulo":"PANTENOL (Pró-Vitamina B5) — Calmante Universal","corpo":"**O que faz:** humectante, cicatrizante (regenera epitélio), anti-inflamatório, melhora elasticidade, soothing.\n**Para quem serve:** todos. Um dos ingredientes mais seguros e eficazes. Excelente em produtos pós-sol, pós-procedimento, peles sensíveis.","tipo":"texto"},{"titulo":"ESQUALANO — Óleo para Todos os Tipos","corpo":"**O que é:** Forma saturada e estabilizada do esqualeno (lipídio natural da pele). Hoje extraído de oliva ou cana-de-açúcar.\n**Diferencial único:** óleo com textura seca, não comedogênico — adequado até para peles oleosas. Fortalece barreira, antioxidante, estabiliza formulações.\n**Um dos raros óleos indicados para pele oleosa acneica.**","tipo":"texto"},{"titulo":"SNAIL MUCIN — Cicatrizante Multifuncional","corpo":"**O que é:** Secreção filtrada de Helix aspersa. Composição: glicoproteínas + proteoglicanos + ácido hialurônico + alantoína + colágeno + elastina + antimicrobianos naturais.\n**O que faz:** hidratação intensa, cicatrização acelerada (acne, cicatrizes), estímulo de colágeno, suavização de textura, redução de manchas PIH, anti-inflamatório.\n**Produto ícone:** Cosrx Advanced Snail 96 Mucin Power Essence — mais de 20 milhões de unidades vendidas globalmente.\n**Quem não deve usar:** possível alergia a moluscos (verificar com cliente que tem alergia a frutos do mar).","tipo":"texto"},{"titulo":"COLÁGENO TÓPICO — O Maior Mito do Skincare","corpo":"**IMPORTANTE:** Colágeno tópico **NÃO reposiciona colágeno na derme**. A molécula é grande demais para penetrar além da superfície.\n**O que realmente faz:** atua como humectante (retém água na superfície), forma filme protetor, efeito temporário de plumping.\n**Para estimular colágeno de verdade:** retinol, vitamina C, peptídeos, PDRN.\n**Como vender sem enganar:** \"Esse produto com colágeno hidrolisado vai deixar a pele mais macia e hidratada imediatamente. Para estimular colágeno de dentro para fora, o que funciona mesmo são os peptídeos e o retinol — temos esse sérum aqui que faz exatamente isso.\"","tipo":"texto"},{"titulo":"GINSENG — Antioxidante Premium","corpo":"**O que é:** Raiz de Panax ginseng com compostos ginsenosídeos. Usado há milênios na medicina oriental.\n**O que faz:** antioxidante potente, estimula circulação, anti-inflamatório, estimula colágeno, iluminador, adaptogênico.\n**Marcas famosas:** Sulwhasoo, Innisfree, Beauty of Joseon (Dynasty Cream).","tipo":"texto"},{"titulo":"ARROZ — O Segredo Histórico","corpo":"**Formas:** água de arroz (rica em inositol/B8, aminoácidos), óleo de farelo de arroz (gama-oryzanol antioxidante), extrato (uniformizador).\n**Base histórica:** observação de que trabalhadoras com arroz tinham pele notavelmente luminosa levou a pesquisas formais.\n**Marcas coreanas:** Beauty of Joseon (Rice + Probiotics), I''m From Rice.","tipo":"texto"},{"titulo":"Guia de Compatibilidade — Pode Combinar","corpo":"- Ingrediente A — Ingrediente B — Observação\n- Niacinamida — HA — Sinergia perfeita\n- Niacinamida — Ceramidas — Potencializa barreira\n- Centella — Qualquer coisa — Universalmente compatível\n- Snail Mucin — Qualquer coisa — Excelente base antes de ativos\n- Esqualano — Qualquer coisa — Pode ser adicionado em qualquer etapa","tipo":"texto"}]'::jsonb, 10),
('2ad42947-710c-4b48-a790-44843528a1b7', NULL, '30c04aa1-9fc3-4c29-8552-f416d6a258ae', 'Ingredientes de Tratamento — Manchas e Anti-Aging', 'texto', NULL, NULL, 0, false, '[{"titulo":"VITAMINA C — Antioxidante e Clareador","corpo":"**O que é:** Ácido ascórbico e derivados. O antioxidante mais estudado em skincare.\n**O que faz:**\n- Antioxidante — neutraliza radicais livres gerados por UV e poluição\n- Inibe tirosinase → reduz produção de melanina → clareia manchas\n- Cofator essencial na síntese de colágeno (sem vitamina C, fibroblastos não produzem colágeno estável)\n- Fotoproteção indireta (antioxidante potencializa SPF)\n- Melhora luminosidade e uniformidade do tom","tipo":"texto"},{"titulo":"Derivados e suas características","corpo":"- Forma — Estabilidade — Eficácia — Irritação\n- Ácido Ascórbico (L-AA) — Baixa (oxida fácil) — Máxima — Média-Alta\n- Ascorbyl Glucoside — Alta — Boa — Baixa\n- Ethyl Ascorbic Acid — Alta — Alta — Baixa\n- 3-O-Ethyl Ascorbic Acid — Alta — Alta — Baixa\n- Ascorbyl Tetraisopalmitate — Muito Alta — Lipossolúvel, boa — Mínima\n**Estabilidade — o maior desafio:** ácido ascórbico puro oxida em contato com luz e ar (produto fica amarelo-laranja → marrom = oxidado = inativo). Armazenar em frasco escuro, fechar bem.\n**Horário:** manhã (antioxidante máximo). **Concentração eficaz:** 10–20% de L-AA; 5–15% para derivados estáveis.\n**Combinações:** com vitamina E + ferúlico (sinergia antioxidante clássica). Com niacinamida (manhã). Com SPF.\n**Não combinar na mesma aplicação:** com retinol (pH incompatível), com benzoil peróxida (oxida).","tipo":"texto"},{"titulo":"RETINOL — Anti-Aging Rei","corpo":"**Hierarquia dos retinoides (mais suave ao mais potente):**\nRetinyl Palmitate → Retinol → Retinaldehyde (Retinal) → Tretinoin (prescrição)\n**O que faz:**\n- Acelera turnover celular (células mortas esfoliam mais rápido)\n- Estimula fibroblastos a produzir mais colágeno\n- Inibe enzimas MMP que degradam colágeno\n- Normaliza queratinização (antiacne)\n- Reduz hiperpigmentação e linhas finas\n**Quem não deve usar:** grávidas e lactantes (categoria X), pele com barreira comprometida, rosácea severa ativa.\n**Efeitos colaterais esperados (purging — 4–8 semanas):** descamação, vermelhidão, ressecamento, eventual piora temporária da acne.\n**Como minimizar:** começar com concentração baixa (0,025–0,1%), usar 1–2x/semana, buffer (\"sandwich method\" = hidratante antes do retinol), usar à noite.\n**Horário:** exclusivamente noturno. **Concentração eficaz sem prescrição:** 0,025–1%.","tipo":"texto"},{"titulo":"BAKUCHIOL — Retinol Sem Irritação","corpo":"**O que é:** Extrato natural da planta Psoralea corylifolia (babchi). Agonista dos mesmos receptores do retinol.\n**Por que é diferente do retinol:**\n- Não causa purging\n- Não fotossensibiliza (pode usar manhã e noite)\n- Seguro na gravidez\n- Tolerado por peles sensíveis\n**Eficácia vs. retinol:** estudo de 2018 no British Journal of Dermatology mostrou eficácia comparável para linhas e hiperpigmentação após 12 semanas, com significativamente menos irritação.\n**Concentração eficaz:** 0,5–2%. **Tempo para resultados:** 8–12 semanas.","tipo":"texto"},{"titulo":"PEPTÍDEOS — Firmeza Sem Irritação","corpo":"**O que são:** Cadeias curtas de aminoácidos que atuam como \"mensageiros\" na pele.\n- Tipo — Mecanismo — Exemplo\n- Sinalização — Instrui fibroblastos a produzir colágeno — Palmitoyl Pentapeptide-4 (Matrixyl)\n- Neurotransmissor-like — Relaxa tensão muscular (alternativa botox) — Argireline (Acetyl Hexapeptide-3)\n- Carreadores — Transportam minerais para a pele — GHK-Cu (cobre)\n**Diferencial:** não irritam. Podem ser usados com qualquer ativo. Perfeitos para peles que não toleram retinol.\n**Peptídeo de cobre (GHK-Cu):** especialmente eficaz para cicatrização e remodelamento de colágeno. Cor azul-verde característica (normal).\n**Argireline:** peptídeo neuromimético — relax muscular localizado. Alternativa suave ao botox tópico. Mais eficaz em linhas de expressão (testa, ao redor dos olhos).\n**Horário:** manhã e/ou noite. **Tempo para resultados:** 8–16 semanas.","tipo":"texto"},{"titulo":"PDRN — Polinucleotídeos","corpo":"**O que é:** Fragmentos de DNA extraídos de esperma de salmão. Sigla: PolyDeoxyRiboNucleotide.\n**O que faz:**\n- Ativa receptor A2A de adenosina → estimula cicatrização e renovação celular\n- Aumenta proliferação de fibroblastos → mais colágeno e elastina\n- Estimula angiogênese → melhor nutrição da pele\n- Anti-inflamatório potente e cicatrizante\n**Contexto:** famoso nas clínicas estéticas como injeção (skinbooster). Agora disponível em tópicos.\n**Argumento de venda:** \"Esse ingrediente era só injetável — era o que chamavam de biorevitalização nas clínicas. Agora vem em sérum para uso em casa.\"\n**Tendência:** um dos ingredientes mais em alta em K-beauty 2024–2025. Marcas: Torriden, Cosrx, Anua.\n**Quem não deve usar:** possível alergia a proteínas de peixe.","tipo":"texto"},{"titulo":"ÁCIDO TRANEXÂMICO — Especialista em Melasma","corpo":"**O que é:** Originalmente medicamento hemostático. Inibe produção de melanina via mecanismo diferente da tirosinase.\n**O que faz:** Inibe ativação de plasminogênio → reduz estimulação de melanócitos. Especialmente eficaz para melasma. Anti-inflamatório e reduz vermelhidão.\n**Diferencial:** mecanismo diferente da vitamina C e niacinamida. Combinados, efeito depigmentante sinérgico.\n**Stack completo para manchas:** tranexâmico + niacinamida + vitamina C + SPF rigoroso.\n**Seguro na gravidez** (oral é usado para hemorragia pós-parto). **Concentração eficaz tópica:** 2–5%.","tipo":"texto"},{"titulo":"ARBUTIN — Clareador Seguro","corpo":"**O que é:** Glicosídeo da hidroquinona. Existe em forma alpha (mais potente) e beta.\n-  — Alpha-Arbutin — Beta-Arbutin\n- Eficácia — 10x mais eficaz — Moderada\n- Estabilidade — Mais estável — Menos estável\n- Preço — Mais caro — Mais barato\n**Diferencial:** clareador potente com perfil de segurança excelente — mais seguro que hidroquinona para fototipos médios a escuros.\n**Concentração eficaz:** alpha-arbutin 0,5–2%, beta-arbutin 1–3%.","tipo":"texto"},{"titulo":"COENZIMA Q10 (Ubiquinona) — Anti-Oxidante Energizante","corpo":"**O que faz:** antioxidante poderoso, energiza células, reduz linhas finas, melhora firmeza, fotoproteção indireta. Declina com a idade — mais relevante em peles maduras.","tipo":"texto"},{"titulo":"EGF — Fator de Crescimento Epidérmico","corpo":"**O que faz:** acelera renovação celular, cicatrização, estímulo de colágeno e elastina, rejuvenescimento celular profundo.\n**Em K-beauty:** muito usado em séruns premium e ampoules anti-aging.\n**Debate científico:** penetração tópica questionada — mas estudos mostram efeito. Não usar em peles com histórico de câncer (por precaução).","tipo":"texto"},{"titulo":"CAFEÍNA — Para Olheiras e Inchaço","corpo":"**O que faz:** vasoconstritora (reduz edema, olheiras vasculares), antioxidante, anti-inflamatória, decompõe triglicerídeos (olheiras gordurosas, celulite).\n**Produto ícone:** The Ordinary Caffeine Solution 5% + EGCG — bestseller para olheiras.","tipo":"texto"},{"titulo":"Guia de Compatibilidade — Anti-Aging","corpo":"- Pode combinar — Observação\n- Bakuchiol + Vitamina C — Sem problema — bakuchiol não é fotossensibilizante\n- Retinol + Niacinamida — Niacinamida mitiga irritação do retinol\n- Retinol + Peptídeos — Anti-aging reforçado\n- Vitamina C (manhã) + Retinol (noite) — A dupla anti-aging mais estudada\n- Tranexâmico + Niacinamida + Vitamina C — Stack sinérgico para manchas\n- Evitar na mesma aplicação — Por quê\n- Vitamina C + Retinol — pH incompatível; usar manhã e noite respectivamente\n- Retinol + Benzoil Peróxida — Oxida e inativa o retinol\n- Vitamina C + Benzoil Peróxida — Oxida a vitamina C\n- Múltiplos ativos novos ao mesmo tempo — Impossível isolar reação adversa","tipo":"texto"}]'::jsonb, 10),
('111a813f-ade1-4d16-94a8-a3b4c316afc7', NULL, '8a2ea0c9-223d-4109-9318-9f0f2deabf67', 'Ácidos e Botânicos Coreanos', 'texto', NULL, NULL, 0, false, '[{"titulo":"AHA (Alpha Hydroxy Acids) — Esfoliação Química","corpo":"**O que são:** Ácidos de origem natural. Esfoliantes químicos que atuam na superfície. **Hidrossolúveis.**\n- Ácido — Fonte — Molécula — Benefício principal\n- Glicólico — Cana-de-açúcar — Menor (mais penetração) — Anti-aging, manchas, textura\n- Láctico — Leite fermentado — Médio — Hidratante + esfoliante, gentil\n- Mandélico — Amêndoas — Maior (mais gentil) — Acne, pele sensível, tons escuros\n- Cítrico — Frutas cítricas — Grande — pH adjuster, antioxidante leve\n**O que fazem:** dissolvem ligações entre corneócitos mortos (esfoliação), aceleram turnover, melhoram textura, uniformidade, luminosidade, estimulam colágeno (glicólico), reduzem hiperpigmentação.\n**Fotossensibilização:** AHAs aumentam sensibilidade ao sol. **SPF obrigatório quando usar AHA na rotina.**\n**Concentração eficaz:** 5–15% (acima de 20% é peel profissional).\n**Horário:** noite. **Quem não deve usar:** barreira comprometida, rosácea severa, pele muito sensível sem adaptação gradual.","tipo":"texto"},{"titulo":"BHA (Beta Hydroxy Acid) — Especialista em Poros","corpo":"**O que é:** Ácido salicílico (praticamente o único BHA usado em cosméticos). **Lipossolúvel.**\n**Diferença crucial do AHA:** BHA é lipossolúvel → penetra no folículo sebáceo (gorduroso como o sebo). AHA é hidrossolúvel → atua apenas na superfície.\n**O que faz:**\n- Dissolve cravos de dentro para fora\n- Exfolia dentro do poro\n- Antibacteriano contra C. acnes\n- Anti-inflamatório\n- Reduz oleosidade\n**Para quem serve:** pele oleosa, acneica, poros dilatados, cravos.\n**Quem não deve usar:** grávidas (por convenção), alergia à aspirina (mesmo composto), barreira muito comprometida.\n**Combinações:** com niacinamida (sinergia para acne oleosa), com centella asiatica (BHA ataca a acne, centella calma a inflamação).\n**Concentração eficaz:** 0,5–2%. **Horário:** preferencialmente noite.","tipo":"texto"},{"titulo":"PHA (Poly Hydroxy Acid) — Esfoliação Ultra-Suave","corpo":"**O que é:** Evolução dos AHAs. Moléculas maiores = penetração mais superficial = menos irritação.\n**Principais:** Gluconolactona, Lactobionic acid, Galactose.\n**Diferencial:**\n- Esfoliação suavíssima da superfície\n- Hidratação (moléculas grandes retêm água)\n- Antioxidante e prebiótico (suporta microbioma)\n**Para quem serve:** pele muito sensível que não tolera AHA, rosácea, fototipos médios a escuros (menor risco de PIH induzida pela esfoliação).","tipo":"texto"},{"titulo":"ÁCIDO AZELAICO — Multifuncional e Único para Rosácea","corpo":"**O que é:** Ácido dicarboxílico produzido por levedura Malassezia furfur.\n**Único ingrediente com evidência clínica aprovada para rosácea.**\n**O que faz:**\n- Antiacne (antimicrobiano, anti-inflamatório, regula queratinização)\n- Clareia manchas (inibe tirosinase)\n- Trata rosácea\n- Reduz vermelhidão\n**Vantagem única:** funciona para inflamação E manchas simultaneamente. **Seguro na gravidez (categoria B).**\n**Concentração eficaz:** 10% (cosmético) a 20% (prescrito para rosácea).","tipo":"texto"},{"titulo":"HEARTLEAF (Houttuynia cordata) — A Nova Centella","corpo":"**O que é:** Planta herbácea com longa história na medicina asiática. Em coreano: 어성초 (eoseongcho).\n**O que faz:**\n- Anti-inflamatório extremamente potente\n- Antibacteriano (C. acnes)\n- Antioxidante e purificante de poros\n- Calmante e soothing\n**Tendência:** explosão de popularidade em 2023–2024 como alternativa mais potente à centella. Produto viral: **Anua Heartleaf 77% Soothing Toner** — 77% de extrato de heartleaf.\n**Para quem serve:** pele acneica com inflamação, sensível com vermelhidão.","tipo":"texto"},{"titulo":"MUGWORT (Artemisia / Ssuk 쑥) — Anti-Inflamatório Botânico","corpo":"**O que faz:** calmante e anti-inflamatório, antioxidante (rico em flavonoides), antibacteriano, regula sebo, suporta barreira cutânea.\n**Tendência:** um dos ingredientes em maior crescimento em K-beauty 2023–2025. Marcas: isntree, Cosrx, Ma:nyo, Benton.","tipo":"texto"},{"titulo":"PRÓPOLIS — Antimicrobiano Natural","corpo":"**O que é:** Resina produzida por abelhas para vedar a colmeia. Rica em flavonoides e ácidos fenólicos.\n**O que faz:** antimicrobiano, anti-inflamatório, antioxidante, cicatrizante, umectante leve.\n**Produto ícone:** Cosrx Propolis Light Ampule — bestseller global.\n**Quem não deve usar:** possível alergia a produtos de colmeia/mel.","tipo":"texto"},{"titulo":"TEA TREE (Melaleuca alternifolia) — Antimicrobiano Clássico","corpo":"**O que faz:** antimicrobiano de amplo espectro, anti-inflamatório, antifúngico.\n**CUIDADO:** óleo puro (100%) é irritante — nunca aplicar puro na pele. Usar em formulações diluídas a 5% ou menos.\nPara clientes que querem \"algo natural\" para acne: tea tree em formulação adequada. Mas niacinamida + BHA têm melhor evidência clínica.","tipo":"texto"},{"titulo":"LICORICE (Alcaçuz / Glycyrrhiza) — Clareador Seguro","corpo":"**O que é:** Extrato de raiz de alcaçuz. Principal composto: glabridina.\n**O que faz:** inibe tirosinase (clareador), anti-inflamatório, antioxidante, soothing.\n**Diferencial:** clareador potente com excelente perfil de segurança — incluindo para fototipos médios a escuros.","tipo":"texto"},{"titulo":"MADECASSOSIDE — Composto Isolado de Centella","corpo":"**O que é:** Composto isolado da centella asiatica — mais concentrado e previsível que o extrato completo.\n**O que faz:** anti-inflamatório potente, cicatrizante, estimula colágeno tipo I, reforça barreira, calmante imediato.\n**Para quem serve:** pele pós-procedimento, acne inflamada, queimaduras solares, sensível.","tipo":"texto"},{"titulo":"Guia Rápido — Ácidos: Qual Usar para Qual Problema","corpo":"- Problema — Ácido Indicado — Por quê\n- Cravos e poros — BHA (salicílico) — Lipossolúvel, penetra no poro\n- Textura e luminosidade — AHA (glicólico ou láctico) — Esfoliação superficial eficaz\n- Pele sensível que quer esfoliação — PHA ou mandélico — Moléculas maiores, menos irritação\n- Rosácea — Azelaico — Único com evidência clínica aprovada\n- Acne + manchas simultâneos — Azelaico — Trata os dois ao mesmo tempo\n- Pele negra/morena com acne — Mandélico ou PHA — Menor risco de PIH","tipo":"texto"}]'::jsonb, 10),
('ab7b2cd6-c841-41a3-ad02-b294f8fbce68', NULL, 'bf44c072-5dff-4305-a520-62acee7ebde7', 'Rotina Coreana Completa', 'texto', NULL, NULL, 0, false, '[{"titulo":"5.1 — A Lógica por Trás da Rotina","corpo":"A rotina coreana não é uma lista aleatória de produtos. É um sistema com lógica interna precisa.\n**Princípios da sequência:**\n- Do mais leve ao mais pesado — textura e consistência guiam a ordem\n- Do mais aquoso ao mais oleoso — produtos aquosos primeiro, depois emolientes e oclusivos\n- Do pH mais baixo ao mais alto — ativos em pH baixo (vitamina C, AHAs) antes de hidratantes neutros\n- Da maior penetração à menor — ativos que precisam penetrar fundo vêm antes de películas que selam","tipo":"texto"},{"titulo":"PASSO 1 — Oil Cleanser (Limpeza com Óleo)","corpo":"**Por quê:** lei da química — \"semelhante dissolve semelhante\". Óleo dissolve sebo, protetor solar, base, maquiagem à prova d''água. Água sozinha não dissolve esses resíduos oleosos.\n**Técnica:** mãos e rosto secos → 3–4 pumps → massagear em movimentos circulares → adicionar um pouco de água (óleo emulsifica e fica leitoso) → enxaguar bem.\n- Tipo — Textura — Ideal para\n- Balm — Sólido que derrete — Pele seca, maquiagem pesada\n- Óleo puro — Líquido — Todos os tipos\n- Cleansing Water/Oil — Leve, emulsiona rapidamente — Pele oleosa, maquiagem leve\n**Óleos não comedogênicos (pele acneica):** esqualano, jojoba, argan, girassol, camélia.\n**Argumento de venda:** \"O óleo aqui é o primeiro passo — ele dissolve protetor e maquiagem. Mas ele não remove a sujeira aquosa. Por isso a dupla funciona: óleo primeiro, espuma depois.\"","tipo":"texto"},{"titulo":"PASSO 2 — Second Cleanser (Espuma/Gel)","corpo":"**Por quê:** remove resíduo do óleo e limpa base aquosa (suor, poluição, bactérias).\n**O que procurar:** pH entre 4,5–5,5. Surfactantes suaves: cocamidopropyl betaine, sodium cocoyl isethionate, amino acid surfactants. Evitar SLS em pele seca/sensível.\n- Tipo — Para quem\n- Gel — Oleosa/mista\n- Espuma — Oleosa/normal\n- Leite / Creme — Seca/sensível\n- Low pH Cleanser — Todos que querem otimizar pH\n**Temperatura:** água morna a fria. Água quente dilata capilares, piora rosácea e ressecamento.","tipo":"texto"},{"titulo":"PASSO 3 — Tônico","corpo":"**Tônico coreano ≠ tônico ocidental** (que tinha álcool + adstringente = resseca e irrita).\n**Funções do tônico coreano:** reequilibra pH após limpeza; primeira camada de hidratação; \"prepara o terreno\" — pele levemente úmida absorve melhor os próximos produtos.\n- Tipo — Função\n- Hydrating Toner — Primeira hidratação\n- First Treatment Essence (FTE) — Tratamento + hidratação base via fermentação\n- Exfoliating Toner — AHA/BHA — esfoliação leve diária\n- Calming Toner — Centella, heartleaf — anti-inflamatório\n- Brightening Toner — Niacinamida, vitamina C — uniformização\n**Técnica 7 Skin Method:** aplicar tônico hidratante em 7 camadas finas, batendo levemente na pele para absorção. Hidratação profunda e acumulativa.","tipo":"texto"},{"titulo":"PASSO 4 — Essence","corpo":"**O que é:** camada de tratamento mais leve que sérum. Textura aquosa, altamente concentrada em ativos fermentados ou de tratamento base. Criação da indústria coreana — não existe equivalente ocidental.\n**Técnica de aplicação:** hands pressing — derramar na palma das mãos e pressionar delicadamente no rosto (não esfregar).\n**Produto ícone:** Missha Time Revolution First Treatment Essence — alternativa acessível ao SK-II.","tipo":"texto"},{"titulo":"PASSO 5 — Ampoule","corpo":"**O que é:** concentração máxima de ativo específico. Dose intensiva de tratamento.\n**Diferença entre ampoule e sérum:**\n- Ampoule: concentração mais alta, uso em ciclos (28 dias), textura mais densa\n- Sérum: uso diário contínuo, concentração moderada\n**Quando usar ampoule:** problema específico intenso, ciclos de 2–4 semanas, boost antes de evento especial.","tipo":"texto"},{"titulo":"PASSO 6 — Sérum","corpo":"**A espinha dorsal do tratamento em qualquer rotina.**\n- Objetivo — Ingrediente-chave — Horário\n- Manchas — Vitamina C, tranexâmico, niacinamida — Manhã (vitamina C) ou noite\n- Acne — BHA, niacinamida, tea tree — Noite\n- Anti-aging — Retinol, peptídeos, PDRN — Noite\n- Hidratação — HA multi-molecular — Manhã e noite\n- Firmeza — Peptídeos, EGF — Noite\n- Glass skin — Niacinamida, HA, pantenol — Manhã e noite\n**Estratégia de venda:** nunca venda um sérum isolado. Sérum precisa de tônico antes e hidratante depois para funcionar. Rotina mínima de 3 produtos.","tipo":"texto"},{"titulo":"PASSO 7 — Eye Cream","corpo":"**Por quê separa:** pele ao redor dos olhos é 3–5x mais fina que o resto do rosto. Requer fórmula específica de menor concentração de ativos e maior hidratação.\n**Técnica:** aplicar com dedo anelar (menos pressão), batidas suaves de dentro para fora.\n- Problema — Ingrediente\n- Olheiras vasculares — Cafeína, vitamina K\n- Olheiras pigmentares — Vitamina C, niacinamida\n- Bolsas — Cafeína, drenagem\n- Linhas — Peptídeos, bakuchiol, retinol baixíssima concentração","tipo":"texto"},{"titulo":"PASSOS 8 e 9 — Emulsão e Creme","corpo":"**Emulsão (lotion):** textura leve — mais pesado que sérum, mais leve que creme. Para pele oleosa a mista em climas quentes. Primeira camada de selagem sem textura pesada.\n**Creme (moisturizer):** hidratante mais denso. Sela todos os passos anteriores. Não é redundante — é o \"selador final\" que diminui TEWL e maximiza absorção do que foi aplicado.\n- Tipo de pele — Textura ideal — Ingredientes-chave\n- Seca — Rich cream, balm — Ceramidas, shea butter, esqualano\n- Oleosa — Gel, gel-cream — Niacinamida, aloe, oil-free\n- Mista — Lotion, fluido — Balanceado\n- Sensível — Creme simples, sem fragrance — Ceramidas, centella, pantenol\n- Madura — Creme nutritivo — Colágeno, peptídeos, ceramidas","tipo":"texto"},{"titulo":"PASSO 10 — SPF (Somente Manhã)","corpo":"**O mais importante de todos os passos. Sem discussão.**\n**SPF — o que os números significam:**\n- SPF 30: bloqueia 97% dos raios UVB\n- SPF 50: bloqueia 98% dos raios UVB\n- UVB: queima, causa câncer (SPF mede proteção contra UVB)\n- UVA: envelhece, mancha, penetra vidro e nuvens (buscar PA+++ no rótulo ou \"broad spectrum\")\n**Quantidade adequada:** ½ colher de chá para o rosto (2mg/cm²) — muito mais que a maioria usa.\n**Reaplicação:** a cada 2 horas em exposição direta.\n**Diferencial do SPF coreano:** textura notavelmente superior — formulações gel aquoso, sérum, cushion. Clientes que \"não toleram protetor\" frequentemente se adaptam ao SPF coreano.\n**Argumento de venda:** \"80% do envelhecimento visível é causado pelo sol. Nenhum sérum anti-aging compensa a falta de SPF. O protetor é o produto mais anti-aging que existe.\"","tipo":"texto"},{"titulo":"Rotina Noturna e Sleeping Mask","corpo":"À noite: remove proteção solar e maquiagem (double cleanse), fase de repair e regeneração, sem SPF. Pode adicionar: retinol, AHA/BHA, peptídeos.\n**Sleeping Mask:** máscara para dormir como último passo noturno. Cria película oclusiva que maximiza absorção. Usar 2–3x por semana ou sempre que pele precisar de boost. Não lavar antes de dormir — o objetivo é manter em contato com a pele.","tipo":"texto"},{"titulo":"Sheet Mask","corpo":"**O que é:** máscara de tecido impregnada com essence/sérum. Oclusão temporária que aumenta absorção dos ativos.\n**Tempo:** 15–20 minutos. Mais que isso pode ressecar (tecido seca e começa a puxar água da pele).\n**Após retirar:** não lavar. Bater o excesso de essence na pele. Aplicar creme em seguida.\n**Como vender:** \"Funciona como 5 dias de sérum em 20 minutos — a oclusão do tecido faz o ativo penetrar muito mais fundo.\"","tipo":"texto"},{"titulo":"Rotinas Adaptadas por Necessidade","corpo":"**Rotina Mínima (3 Passos) — iniciantes, viagens, pele em recovery:**\n- Cleanser suave\n- Hidratante com ceramidas + niacinamida\n- SPF (manhã) ou sleeping mask (noite)\n**Rotina Intermediária (5 Passos):**\n- Limpeza (oil + water se maquiagem)\n- Tônico hidratante\n- Sérum de tratamento\n- Hidratante\n- SPF (manhã) ou sleeping mask (noite)","tipo":"texto"}]'::jsonb, 10),
('9dcdcdf6-7941-4dba-a0ad-cf032cde98ae', NULL, '605e50b8-e5f9-4ee3-b7a1-dd05f225b2d7', 'Marcas de K-Beauty — 14 Marcas Essenciais', 'texto', NULL, NULL, 0, false, '[{"titulo":"Mapa do Mercado Coreano","corpo":"**Conglomerados principais:**\n- **Amorepacific Group:** Sulwhasoo, Laneige, Innisfree, Etude, IOPE, Hera\n- **LG H&H:** History of Whoo, SU:M37, O HUI, Belif, VDL\n- **Independentes/Emergentes:** Cosrx, Some By Mi, Torriden, Beauty of Joseon, Anua, Purito, Benton, Isntree, Ma:nyo, Dr. Jart+","tipo":"texto"},{"titulo":"COSRX — Funcional Minimalista","corpo":"**Posicionamento:** skincare funcional, minimalista, orientado por ingredientes. Sem fragrância desnecessária, sem marketing vazio. Nome: Cosmetics + RX (receita médica).\n**Produtos campeões:**\n- Advanced Snail 96 Mucin Power Essence — mais de 20 milhões de unidades vendidas globalmente\n- BHA Blackhead Power Liquid — referência em tônico de ácido salicílico\n- AHA 7 Whitehead Power Liquid\n- Propolis Light Ampule\n**Cliente ideal:** homens e mulheres que querem skincare que funciona sem frescura. Iniciantes confiantes. Quem pesquisa ingredientes.\n**Script de venda:** \"Cosrx é o favorito dos skincare enthusiasts do mundo inteiro — não por marketing, mas porque as fórmulas são limpas e funcionam. O Snail Mucin de 96% é o produto mais copiado no K-beauty.\"","tipo":"texto"},{"titulo":"BEAUTY OF JOSEON — Heritage + Moderno","corpo":"**Posicionamento:** fusão de raízes históricas coreanas (era Joseon, Hanbang) com biotecnologia moderna. Ingredientes: arroz, ginseng, mel.\n**Produtos campeões:**\n- **Relief Sun: Rice + Probiotics (SPF 50+ PA++++)** — considerado um dos melhores SPFs do mercado global; viral no TikTok por textura extraordinária\n- Glow Serum: Propolis + Niacinamide\n- Dynasty Cream (ginseng)\n- Revive Eye Serum (Ginseng + Retinal)\n**Script de venda:** \"Beauty of Joseon é inspirada em receitas de beleza da era Joseon — coisas que as mulheres coreanas usavam há 600 anos, reformuladas com biotecnologia moderna. O protetor solar deles é basicamente a textura mais agradável de SPF que existe.\"","tipo":"texto"},{"titulo":"SOME BY MI — Resultados Rápidos","corpo":"**Posicionamento:** skincare para pele problemática com foco em resultados visíveis em tempo determinado. Linhas temáticas, embalagens chamativas.\n**Produto campeão:** **AHA BHA PHA 30 Days Miracle Toner** — produto que colocou a marca no mapa global. Tônico com 3 ácidos (exfoliação + calming).\n**Cliente ideal:** jovens com acne, pele problemática, quem quer resultado em curto prazo.\n**Script de venda:** \"Some By Mi é a marca do ''antes e depois'' — o tônico com 3 ácidos é o que as pessoas mostram quando falam em transformação de acne. Funciona porque combina esfoliação química com calming.\"","tipo":"texto"},{"titulo":"LANEIGE — Hidratação Intensa","corpo":"**Posicionamento:** hidratação intensiva. \"Water science\". Nível premium acessível.\n**Produtos campeões:**\n- **Lip Sleeping Mask** — criou a categoria de tratamento labial noturno. Um dos produtos mais fotografados no Instagram beauty.\n- **Water Sleeping Mask** — sleeping mask mais vendido do mundo\n**Script de venda:** \"Laneige é a marca do Lip Sleeping Mask — aquele produto que ficou viral porque a pele fica completamente diferente de manhã. A Water Sleeping Mask faz o mesmo para o rosto.\"","tipo":"texto"},{"titulo":"INNISFREE — Natural e Eco-Conscious","corpo":"**Posicionamento:** skincare natural, eco-consciente. Ingredientes exclusivos da Ilha de Jeju (chá verde, camellia, orquídea, água mineral vulcânica). Submarca da Amorepacific.\n**Produto campeão:** **No Sebum Mineral Powder** — controle de oleosidade imediato. Cult product.\n**Cliente ideal:** consumidor eco-consciente, que aprecia ingredientes naturais.","tipo":"texto"},{"titulo":"DR. JART+ — Dermocosmético","corpo":"**Posicionamento:** híbrido dermocosmético. Ingredientes clínicos com fórmulas elegantes. Pioneira no conceito de dermocosméticos coreanos (fundada em 2004).\n**Produto campeão:** **Cicapair Tiger Grass Color Correcting Treatment** — corretivo verde que neutraliza vermelhidão e protege. Referência para rosácea.\n**Cliente ideal:** quem tem rosácea, vermelhidão, pele sensível.","tipo":"texto"},{"titulo":"MISSHA — Premium Acessível","corpo":"**Posicionamento:** skincare premium acessível. Famosa por criar alternativas de alta qualidade a produtos luxury.\n**Produto campeão:** **Time Revolution First Treatment Essence** — alternativa ao SK-II (que custa 3–4x mais).\n**Script de venda:** \"Missha criou a alternativa mais famosa ao SK-II — a essência fermentada mais cara do mundo — com resultado comparável por um quarto do preço.\"","tipo":"texto"},{"titulo":"ANUA — Botânico Puro","corpo":"**Posicionamento:** skincare minimalista centrado em ingredientes botânicos puros em alta concentração.\n**Produto campeão:** **Heartleaf 77% Soothing Toner** — viral no TikTok. 77% de extrato de heartleaf.\n**Cliente ideal:** pele acneica, sensível, oleosa com inflamação.\n**Diferencial:** concentração absurda de ingrediente ativo (77% heartleaf). Sem frescura.","tipo":"texto"},{"titulo":"TORRIDEN — Biotecnologia HA","corpo":"**Posicionamento:** skincare baseado em biotecnologia. Foco em micro e nano HA.\n**Produto campeão:** **DIVE-IN Low Molecular Hyaluronic Acid Serum** — referência em HA de baixo peso molecular.\n**Diferencial:** pioneiro em comunicar claramente o peso molecular do HA na embalagem — educação do consumidor como diferencial.","tipo":"texto"},{"titulo":"PURITO — Clean Beauty","corpo":"**Posicionamento:** clean beauty coreano. Ingredientes seguros, formulações gentis, sem ingredientes controversos.\n**Produto campeão:** **Centella Green Level Unscented Sun** — SPF sem fragrance, mineral puro, para pele sensível.\n**Diferencial:** um dos únicos SPFs coreanos unscented com formulação limpa.","tipo":"texto"},{"titulo":"BENTON — Para Pele Sensível","corpo":"**Posicionamento:** skincare para pele sensível e acneica com ingredientes suaves.\n**Produto campeão:** **Snail Bee High Content Essence** — combinação única de snail mucin com veneno de abelha.","tipo":"texto"},{"titulo":"ISNTREE — Custo-Benefício","corpo":"**Posicionamento:** ingredientes naturais em alta concentração, formulações limpas, preço justo.\n**Produto campeão:** Hyaluronic Acid Toner (50% de HA aqua complex) — relação custo-benefício excepcional.","tipo":"texto"},{"titulo":"MA:NYO (Manyo Factory) — Fermentação Avançada","corpo":"**Posicionamento:** biotecnologia de fermentação. Laboratório fundado em 2007. Um dos mais avançados tecnicamente.\n**Produto campeão:** **Bifida Biome Concentrate Ampoule** — microbioma e barreira via fermentação bifidus.\n**Pure Cleansing Oil:** considerado um dos melhores oil cleansers do mercado.","tipo":"texto"},{"titulo":"SULWHASOO — Luxury Hanbang","corpo":"**Posicionamento:** luxury heritage. Fusão de Hanbang com tecnologia avançada. O \"La Mer\" coreano. Fundada em 1966.\n**Produto campeão:** First Care Activating Serum + Concentrated Ginseng Renewing Cream.\n**Faixa de preço:** alta (US$60–200+ por produto).\n**Cliente ideal:** consumidor premium, presente de luxo, cliente que já usa La Mer ou Estée Lauder.","tipo":"texto"},{"titulo":"Tabela Comparativa Rápida","corpo":"- Marca — Posicionamento — Ingrediente Signature — Melhor para\n- Cosrx — Funcional minimalista — Snail Mucin, BHA — Iniciantes, acne\n- Beauty of Joseon — Heritage + moderno — Arroz, Ginseng — Todos, SPF cult\n- Some By Mi — Resultados rápidos — AHA+BHA+PHA — Acne, jovens\n- Laneige — Hidratação intensa — Water technology — Hidratação, lábios\n- Innisfree — Natural/Eco — Chá verde Jeju — Eco-conscious\n- Dr. Jart+ — Clínico — CICA (Centella) — Rosácea, sensível\n- Missha — Premium acessível — Galactomyces — Price-performance\n- Anua — Botânico puro — Heartleaf — Acne inflamada\n- Torriden — Biotecnologia — Micro HA — Hidratação deep\n- Purito — Clean beauty — Centella — Sensível, clean\n- Ma:nyo — Fermentação — Bifidus — Microbioma\n- Sulwhasoo — Luxury Hanbang — Ginseng — Presentes premium","tipo":"texto"}]'::jsonb, 10),
('25c51587-d86e-4c68-b3e9-1f0cbe0d51a8', NULL, '84da0540-1cfe-413b-bacf-2982d2b7bc48', 'Técnicas de Venda em Skincare', 'texto', NULL, NULL, 0, false, '[{"titulo":"O Consultor vs. O Vendedor","corpo":"**Vendedor de produto:** \"Temos esse hidratante. É ótimo. Quer levar?\" **Consultor especialista:** \"Você usa protetor solar diariamente? Qual a maior preocupação da sua pele agora? Me conta mais sobre sua rotina.\"\nA diferença: o consultor vende soluções. O cliente sente que está sendo ajudado, não sendo vendido. Resultado: ticket médio maior, retorno, indicações.","tipo":"texto"},{"titulo":"SPIN Selling Adaptado para Skincare","corpo":"SPIN = Situação, Problema, Implicação, Necessidade de solução. Framework de Neil Rackham para vendas consultivas.","tipo":"texto"},{"titulo":"S — Situação","corpo":"Entender o contexto atual do cliente sem julgamento.\n- \"Você já tem alguma rotina de skincare?\"\n- \"Usa protetor solar todo dia?\"\n- \"Tem algum produto que usa com frequência?\"\n- \"Sua pele ficou diferente depois de [evento: gravidez / mudança de cidade / mudar de anticoncepcional]?\"","tipo":"texto"},{"titulo":"P — Problema","corpo":"Identificar a dor real — o que incomoda, frustra, preocupa.\n- \"O que mais te incomoda na sua pele hoje?\"\n- \"Tem alguma área que você não gosta?\"\n- \"Já tentou algum produto pra isso? Funcionou?\"\n- \"O que você mais gostaria de mudar?\"","tipo":"texto"},{"titulo":"I — Implicação","corpo":"Mostrar as consequências de não resolver o problema. Cria urgência.\n- \"Sem protetor, a mancha tende a escurecer com o tempo — especialmente no verão.\"\n- \"Pele desidratada piora linhas finas e deixa a maquiagem menos uniforme.\"\n- \"Acne com inflamação constante pode deixar marcas mais difíceis de tratar depois.\"\n- \"Barreira comprometida deixa a pele mais reativa a qualquer produto.\"","tipo":"texto"},{"titulo":"N — Necessidade de solução","corpo":"Cliente articula o que precisa — você apresenta a solução como resposta direta.\n- \"Então você quer algo que clareia as manchas mas não irrite?\"\n- \"Você quer uma rotina que caiba no seu tempo de manhã — menos de 5 minutos?\"\n- \"Você quer algo que funcione mesmo sem experiência com skincare?\"\nDepois do N: \"Tenho exatamente o que você precisa.\" — e a recomendação parece feita sob medida.","tipo":"texto"},{"titulo":"Diagnóstico de 5 Perguntas — A Abertura Padrão","corpo":"Independente do cliente, começar sempre com estas 5 perguntas antes de qualquer recomendação:\n- **Qual sua maior preocupação com a pele agora?** (Problema principal)\n- **Sua pele tende a ficar mais oleosa ou mais seca?** (Tipo básico)\n- **Você usa protetor solar todo dia?** (Hábito base + abertura para venda)\n- **Tem algum ingrediente que você sabe que não tolera?** (Restrições)\n- **Você prefere uma rotina simples ou não tem problema com mais passos?** (Complexidade)\nCom 5 respostas: diagnóstico suficiente para recomendar rotina personalizada.","tipo":"texto"},{"titulo":"Cross-sell — Venda Complementar Inteligente","corpo":"**Regra de ouro:** cross-sell serve o cliente, não o caixa. Só adicionar produto que genuinamente melhora o resultado.\n- Produto principal — Cross-sell natural — Por quê faz sentido\n- Protetor solar — Vitamina C matinal — C + SPF = proteção fotoativa máxima\n- Retinol noturno — Ceramidas / barreira — Retinol seca — ceramidas compensam\n- Ácido (AHA/BHA) — Hidratante calmante — Esfoliação + calming evita irritação\n- Sérum anti-manchas — SPF (se não tiver) — Sem SPF, manchas voltam\n- Cleanser — Tônico — Completa a limpeza e equilibra pH\n- Sheet mask — Sleeping mask — Hidratação diária vs. intensiva","tipo":"texto"},{"titulo":"Upsell — Para o Próximo Nível","corpo":"**Quando fazer upsell:** quando o produto de entrada funciona bem e o cliente tem uma preocupação adicional.\n**Exemplos práticos:**\n- Cliente comprou hidratante comum → upsell para hidratante com ceramidas + niacinamida (problema de poros visíveis)\n- Cliente usa Cosrx Snail → upsell para Missha Time Revolution FTE (melhor resultado em 4 semanas)\n- Cliente com SPF básico → upsell para Beauty of Joseon Relief Sun (textura superior, pa++++)\n**Como apresentar upsell sem parecer ganancioso:** \"Esse que você tem funciona. Mas já que você mencionou [preocupação], esse aqui vai te dar resultado mais rápido porque [benefício específico]. A diferença de preço é X — vale pela [razão concreta].\"","tipo":"texto"},{"titulo":"Gestão de Objeções — As 6 Mais Comuns","corpo":"","tipo":"texto"},{"titulo":"1. \"É muito caro\"","corpo":"**Nunca:** \"Mas é muito barato para o que oferece.\" **Sim:** \"Você falou em [problema]. Quanto você já gastou em coisas que não funcionaram? Esse produto foi formulado especificamente pra [benefício]. O custo por uso é de R$ X — menos que um café por dia.\"","tipo":"texto"},{"titulo":"2. \"Sou alérgica / tenho pele sensível\"","corpo":"**Sim:** \"Ótimo que me falou. Então vou te mostrar só produtos sem fragância, com ingredientes comprovadamente gentis — Centella Asiatica, pantenol, ceramidas. Existem opções feitas exatamente pra pele reativa.\"","tipo":"texto"},{"titulo":"3. \"Não tenho tempo para rotina\"","corpo":"**Sim:** \"Entendo. A rotina mínima que funciona são 3 produtos: limpeza + hidratante + protetor. 2 minutos de manhã. Começa pequeno, adiciona mais tarde se quiser.\"","tipo":"texto"},{"titulo":"4. \"Skincare coreano é diferente para a pele brasileira\"","corpo":"**Sim:** \"Pele brasileira tem características parecidas com a coreana — melanina, umidade, sol intenso. Os K-beauty são formulados para esses desafios. Na verdade, o mercado global comprou mais SPF coreano justamente porque funciona melhor em climas quentes.\"","tipo":"texto"},{"titulo":"5. \"Vou pesquisar antes\"","corpo":"**Sim:** \"Boa ideia pesquisar. Se quiser, te mando o nome do ingrediente principal — assim você vai diretamente ao que importa, não perde tempo em comparações genéricas. O [ingrediente X] vai aparecer nos melhores reviews.\"","tipo":"texto"},{"titulo":"6. \"Já tenho produto similar em casa\"","corpo":"**Sim:** \"Que ótimo — significa que você já tem o hábito. Esse aqui tem [diferencial específico] que o que você usa provavelmente não tem. Quer ver o rótulo e comparar os ingredientes?\"","tipo":"texto"},{"titulo":"Fidelização — O Cliente que Volta","corpo":"**Regra dos 3 meses:** a maioria dos produtos de skincare mostra resultado real em 4–12 semanas. Cliente que comprou e não foi orientado sobre prazo vai abandonar antes de ver resultado.\n**Protocolo de fidelização:**\n- **Na venda:** \"Você vai começar a ver diferença em [X semanas]. Se depois de [Y dias] não mudou nada, me fala — ajustamos.\"\n- **Semana 2:** \"Como está o produto? Pele adaptando bem?\"\n- **Mês 1:** \"Como está o resultado? Alguma dúvida da rotina?\"\n- **Mês 3:** \"Hora de reabastecer. Quer adicionar algum passo novo à rotina?\"","tipo":"texto"},{"titulo":"O Argumento dos Ingredientes","corpo":"Cliente informado compra mais e volta. Ensinar 1 ingrediente por venda cria especialista progressivo que depende de você para aprender mais.\n**Script para ensinar enquanto vende:** \"Deixa eu te explicar por que funciona — sem complicar. [Ingrediente] faz exatamente [ação simples] na pele. Por isso vai ajudar com [seu problema específico]. Simples assim.\"","tipo":"texto"}]'::jsonb, 10),
('0ebbb52f-6d6b-4e82-b41c-ab53f249e815', NULL, 'a518639a-9f3b-4b37-846d-9c21e813a836', 'Tendências e Inteligência Comercial', 'texto', NULL, NULL, 0, false, '[{"titulo":"O Mercado Global de K-Beauty em Números","corpo":"- Mercado global K-beauty: US$ 13,4 bilhões (2023)\n- CAGR projetado até 2030: 9,8%\n- Brasil: mercado de cosméticos Top 3 mundial por consumo\n- Ciudad del Este: hub de importação — acesso a marcas coreanas antes de chegarem ao varejo brasileiro convencional","tipo":"texto"},{"titulo":"Tendências K-Beauty 2024–2026","corpo":"","tipo":"texto"},{"titulo":"1. Skinimalism — Menos Produtos, Mais Ingredientes","corpo":"**O que é:** movimento oposto ao 10-step. Rotinas com 3–5 produtos altamente eficazes.\n**Produtos vencedores:** multifuncionais — hidratante com SPF, tônico com ingredientes de sérum, cremes \"all-in-one\".\n**Como vender:** \"Você quer resultado sem complicação? Rotina de 3 produtos que substitui 8.\"","tipo":"texto"},{"titulo":"2. Skin Barrier Repair — A Grande Onda","corpo":"**O que é:** foco em restaurar a barreira cutânea danificada (overexfoliação, estresse, produtos agressivos).\n**Ingredientes em alta:** ceramidas, ácido hialurônico, pantenol, centella, fermentos (bifidus).\n**Por que virou tendência:** pandemia de overexfoliação — muita gente exagerou em ácidos e retinol, agora recuperando a barreira.","tipo":"texto"},{"titulo":"3. Glass Skin — A Pele Espelhada Coreana","corpo":"**O que é:** pele visivelmente hidratada, translúcida, sem poros visíveis, sem manchas. Efeito vidro.\n**Ingredientes:** HA multi-molecular, niacinamida, esqualano, essences fermentadas.\n**Argumento de venda:** \"É a estética de pele mais buscada no mundo agora — e é sobre hidratação profunda, não maquiagem.\"","tipo":"texto"},{"titulo":"4. Micro-Biome Beauty","corpo":"**O que é:** skincare que protege e nutre o microbioma da pele em vez de esterilizá-la.\n**Ingredientes:** bifidus, lactobacillus, postbiotics (fragmentos de bactérias benéficas).\n**Produtos em destaque:** Ma:nyo Bifida Ampoule, Laneige Cica Sleeping Mask.","tipo":"texto"},{"titulo":"5. PDRN e Bio-Fermentation","corpo":"**PDRN:** DNA de salmão — migrou de procedimentos clínicos para séruns de marca. Regeneração e anti-aging intenso.\n**Fermentação avançada:** galactomyces, saccharomyces (Missha, SK-II), bifidus (Ma:nyo). Alta concentração de ativos bioativos via fermentação.","tipo":"texto"},{"titulo":"6. Clean + Eco K-Beauty","corpo":"Consumidor jovem exige: sem parabenos, sem fragância artificial, cruelty-free, embalagem sustentável.\n**Marcas bem posicionadas:** Purito, Torriden, Isntree.","tipo":"texto"},{"titulo":"7. Sunscreen Culture","corpo":"SPF deixou de ser produto funcional e virou objeto de desejo. TikTok popularizou SPF coreano globalmente. Pessoas comparam texturas como colecionam séruns.\n**Top performers:** Beauty of Joseon Relief Sun, Purito Centella Green Level.","tipo":"texto"},{"titulo":"Kits Estratégicos — Venda de Conjuntos","corpo":"Kits aumentam ticket médio, facilitam a decisão, e ensinam o cliente a usar produtos em conjunto corretamente.\n- Kit — Produtos — Para quem — Argumento\n- Kit Iniciante — Low pH cleanser + HA tônico + creme + SPF — Quem nunca teve rotina — \"Rotina completa para começar do zero\"\n- Kit Anti-Acne — BHA tônico + niacinamida sérum + calming cream — Pele acneica/oleosa — \"3 produtos que atacam acne por ângulos diferentes\"\n- Kit Glass Skin — FTE + HA sérum + moisturizer gel + SPF — Quem quer pele hydrated — \"O ritual de glass skin em 4 passos\"\n- Kit Anti-Manchas — Vitamina C + tranexâmico + SPF — Melasma, manchas solares — \"Tríade de clarificação + proteção\"\n- Kit Anti-Aging — Retinol + peptídeos + ceramidas + SPF — Pele madura — \"Repair noturno + proteção diurna\"\n- Kit Presente — Sheet masks variadas + sleeping mask + lip mask — Presentes — \"Experiência de spa em casa\"","tipo":"texto"},{"titulo":"Métricas de Performance — O Que Medir","corpo":"**Ticket médio por atendimento:** meta de pelo menos 2–3 produtos por cliente. Rotina mínima = 3 produtos.\n**Taxa de retorno:** cliente de skincare bem orientada volta em 2–3 meses para reabastecer. Se não volta, investigar por quê.\n**Conversão por diagnóstico:** quantos diagnósticos resultam em venda? Abaixo de 60% — revisar a abordagem.\n**NPS informal:** \"Você indicaria para alguém?\" — cliente que indica é promotora da marca.","tipo":"texto"},{"titulo":"Como Manter-se Atualizado","corpo":"**Plataformas de referência:**\n- **TikTok:** @skincarebyhyram, @doctorly, trendwatching de ingredientes virais\n- **Reddit:** r/SkincareAddiction, r/AsianBeauty — comunidades sérias, reviews reais\n- **YouTube:** Beauty Within (Felicia + Rowena) — educação séria sobre K-beauty\n- **Instagram:** @incidecoder — análise de ingredientes por produto\n- **INCIDecoder.com:** verificar qualquer produto pelo INCI completo","tipo":"texto"},{"titulo":"O Perfil do Consultor de K-Beauty de Alto Nível","corpo":"**Conhecimento:** sabe os ingredientes dos 30 produtos mais vendidos da loja de cor.\n**Diagnóstico:** consegue identificar tipo de pele e 3 principais preocupações em menos de 5 minutos de conversa.\n**Consultivo:** nunca começa pela recomendação — sempre pela pergunta.\n**Atualizado:** acompanha pelo menos 1 fonte de tendências por semana.\n**Fidelizador:** mantém acompanhamento pós-venda. Seus clientes voltam e trazem amigas.","tipo":"texto"},{"titulo":"Pontocom — Vantagem Competitiva","corpo":"Estar em Ciudad del Este com acesso a produtos de importação é uma vantagem real:\n- Acesso a marcas antes de chegarem ao varejo brasileiro\n- Preços mais competitivos que importação individual\n- Variedade de marcas que não existem em farmácias e lojas convencionais do Brasil\n- Consultor treinado = diferencial vs. compra online sem orientação\n**Argumento final:** \"A cliente pode comprar pelo site coreano e esperar 30 dias sem entender o que comprou. Ou pode comprar aqui, com alguém que entende os ingredientes, sabe o que funciona para o tipo de pele dela, e está disponível se precisar ajustar.\"","tipo":"texto"}]'::jsonb, 10);
